Assets::Assets() : mmap_root_(nullptr), mmap_size_(0), assets_(nullptr) {
    // Initialize the assets partition
    esp_err_t err = InitializePartition();
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize assets partition: %s", esp_err_to_name(err));
        return;
    }

    // Validate checksums for all assets in the partition
    if (!ValidateAssetChecksums()) {
        ESP_LOGE(TAG, "Asset checksum validation failed");
        // Optionally clean up and return error
        Cleanup();
        return;
    }

    // Populate the asset table from the memory-mapped region
    PopulateAssetTable();
}

Assets::~Assets() {
    // Unmap the memory-mapped partition if it exists
    if (mmap_handle_ != nullptr) {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = nullptr;
    }

    // Set mmap_root_ to nullptr for safety
    mmap_root_ = nullptr;
}

uint32_t Assets::CalculateChecksum(const char* data, uint32_t length) {
    // Handle edge case of zero length
    if (length == 0) {
        return 0;
    }

    // Handle null pointer case (though caller should ensure valid data)
    if (data == nullptr) {
        return 0;
    }

    // Calculate CRC32 checksum using ESP-IDF's built-in function
    // esp_crc32_le() is optimized for ESP32 and provides good performance
    return esp_crc32_le((uint8_t*)data, length);
}

bool Assets::InitializePartition() {
    // Validate that we have a valid partition handle
    if (!partition_) {
        ESP_LOGE(TAG, "Invalid partition handle");
        return false;
    }

    // Map the partition into memory
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, 
                                       ESP_PARTITION_MMAP_DATA, 
                                       (const void**)&mmap_root_, 
                                       &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map partition: %s", esp_err_to_name(err));
        return false;
    }

    // Check if we have valid mapped memory
    if (!mmap_root_) {
        ESP_LOGE(TAG, "Failed to get valid memory mapping");
        esp_partition_unmap(mmap_handle_);
        return false;
    }

    // Parse the asset table from the mapped memory
    // First, check if we have a valid asset table header
    const mmap_assets_table* table_header = 
        reinterpret_cast<const mmap_assets_table*>(mmap_root_);

    // Validate the magic number and version
    if (table_header->magic != ASSETS_TABLE_MAGIC) {
        ESP_LOGE(TAG, "Invalid asset table magic number");
        esp_partition_unmap(mmap_handle_);
        return false;
    }

    if (table_header->version != ASSETS_TABLE_VERSION) {
        ESP_LOGE(TAG, "Unsupported asset table version");
        esp_partition_unmap(mmap_handle_);
        return false;
    }

    // Calculate the actual number of assets from the table size
    uint32_t num_assets = table_header->num_assets;

    // Clear existing assets list
    assets_.clear();

    // Parse each asset entry in the table
    const mmap_asset_entry* asset_entries = 
        reinterpret_cast<const mmap_asset_entry*>(
            mmap_root_ + sizeof(mmap_assets_table));

    // Validate that we have enough space for all asset entries
    size_t expected_size = sizeof(mmap_assets_table) + 
                          (num_assets * sizeof(mmap_asset_entry));
    if (expected_size > partition_->size) {
        ESP_LOGE(TAG, "Asset table exceeds partition size");
        esp_partition_unmap(mmap_handle_);
        return false;
    }

    // Populate the assets map with metadata
    for (uint32_t i = 0; i < num_assets; ++i) {
        const mmap_asset_entry& entry = asset_entries[i];

        // Validate asset entry parameters
        if (entry.offset + entry.size > partition_->size) {
            ESP_LOGW(TAG, "Invalid asset entry %d: offset or size out of bounds", i);
            continue;
        }

        // Create asset metadata structure
        AssetMetadata metadata;
        metadata.offset = entry.offset;
        metadata.size = entry.size;
        metadata.crc32 = entry.crc32;

        // Copy asset name (ensure null termination)
        char name[ASSETS_MAX_NAME_LENGTH];
        strncpy(name, entry.name, ASSETS_MAX_NAME_LENGTH - 1);
        name[ASSETS_MAX_NAME_LENGTH - 1] = '\0';

        // Add to our assets map
        assets_[std::string(name)] = metadata;
    }

    ESP_LOGI(TAG, "Successfully initialized partition with %zu assets", assets_.size());
    return true;
}

