int Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progressCallback) {
    // Get network instance and create HTTP client
    auto& network = Board::GetInstance().GetNetwork();
    auto http = network.CreateHttpClient();

    if (!http) {
        return -1; // Failed to create HTTP client
    }

    // Configure HTTP headers
    SetupHttp();

    // Perform HTTP GET request
    int statusCode = http->Get(url);
    if (statusCode != 200) {
        http->Close();
        return -2; // HTTP request failed
    }

    // Get content length for progress calculation
    size_t contentLength = http->GetContentLength();
    if (contentLength == 0) {
        http->Close();
        return -3; // Invalid content length
    }

    // Get flash partition info
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_NVS, "assets");

    if (!partition) {
        http->Close();
        return -4; // Failed to find assets partition
    }

    // Determine sector size for erasing
    size_t sectorSize = esp_partition_get_main_flash_sector_size();
    if (sectorSize == 0) {
        http->Close();
        return -5; // Invalid sector size
    }

    // Calculate number of sectors needed
    size_t partitionSize = partition->size;
    size_t numSectors = (partitionSize + sectorSize - 1) / sectorSize;

    // Erase flash sectors
    for (size_t i = 0; i < numSectors; i++) {
        esp_err_t err = esp_partition_erase_range(partition, i * sectorSize, sectorSize);
        if (err != ESP_OK) {
            http->Close();
            return -6; // Failed to erase sector
        }
    }

    // Prepare variables for download tracking
    size_t totalBytesRead = 0;
    size_t lastBytesRead = 0;
    int lastProgress = 0;
    int64_t lastUpdateTime = esp_timer_get_time();
    size_t currentSpeed = 0;

    // Buffer for reading data in chunks
    constexpr size_t CHUNK_SIZE = 1024;
    uint8_t* buffer = new uint8_t[CHUNK_SIZE];

    if (!buffer) {
        http->Close();
        return -7; // Memory allocation failed
    }

    try {
        // Read data in chunks and write to flash
        while (totalBytesRead < contentLength) {
            size_t bytesToRead = std::min(CHUNK_SIZE, contentLength - totalBytesRead);
            int bytesRead = http->Read(buffer, bytesToRead);

            if (bytesRead <= 0) {
                delete[] buffer;
                http->Close();
                return -8; // Read error
            }

            // Write chunk to flash
            esp_err_t err = esp_partition_write(partition, totalBytesRead, buffer, bytesRead);
            if (err != ESP_OK) {
                delete[] buffer;
                http->Close();
                return -9; // Flash write error
            }

            totalBytesRead += bytesRead;

            // Update progress and speed
            int64_t currentTime = esp_timer_get_time();
            if (currentTime - lastUpdateTime >= 1000000) { // Update every second
                currentSpeed = (totalBytesRead - lastBytesRead) * 1000000 / (currentTime - lastUpdateTime);
                lastBytesRead = totalBytesRead;
                lastUpdateTime = currentTime;

                // Calculate progress percentage
                int progress = (int)((double)totalBytesRead / contentLength * 100);
                if (progress > lastProgress) {
                    lastProgress = progress;
                    if (progressCallback) {
                        progressCallback(progress, currentSpeed);
                    }
                }
            }
        }

        // Final progress update
        if (progressCallback && lastProgress < 100) {
            progressCallback(100, currentSpeed);
        }

        // Close HTTP connection
        http->Close();

        // Free buffer
        delete[] buffer;

        // Reinitialize asset partition
        InitializePartition();

        return 0; // Success

    } catch (...) {
        // Cleanup on exception
        delete[] buffer;
        http->Close();
        return -10; // Exception occurred
    }
}

bool Assets::GetAssetData(const std::string &name, void *&data, size_t &size) {
    // Check if asset exists in our map
    auto it = assets_.find(name);
    if (it == assets_.end()) {
        return false;
    }

    // Get the asset entry
    const Asset& asset = it->second;

    // Calculate the actual data pointer (offset by 2 bytes for magic header)
    uint8_t* data_ptr = static_cast<uint8_t*>(mmap_root_) + asset.offset + 2;

    // Verify magic number - check if first 2 bytes are 'Z','Z'
    if (data_ptr[-2] != 'Z' || data_ptr[-1] != 'Z') {
        return false;
    }

    // Set output parameters
    data = data_ptr;
    size = asset.size;

    return true;
}

const char* DeviceStateMachine::GetStateName(DeviceState state) {
  // Bounds checking to ensure the state value is within valid range
  if (state < 0 || state >= kDeviceStateCount) {
    return "Invalid State";
  }

  // Return the corresponding string from the STATE_STRINGS array
  return STATE_STRINGS[state];
}

bool DeviceStateMachine::IsValidTransition(DeviceState from_state, DeviceState to_state) const {
  // Handle self-transition (same state)
  if (from_state == to_state) {
    return true;
  }

  // Define valid transitions based on device state machine logic
  switch (from_state) {
    case kDeviceStateUnknown:
      // Only valid transition from Unknown is to Starting
      return to_state == kDeviceStateStarting;

    case kDeviceStateStarting:
      // Only valid transition from Starting is to WifiConfiguring
      return to_state == kDeviceStateWifiConfiguring;

    case kDeviceStateWifiConfiguring:
      // Only valid transition from WifiConfiguring is to Idle
      return to_state == kDeviceStateIdle;

    case kDeviceStateIdle:
      // Valid transitions from Idle
      return (to_state == kDeviceStateConnecting ||
              to_state == kDeviceStateListening ||
              to_state == kDeviceStateActivating);

    case kDeviceStateConnecting:
      // Connecting can transition to Listening or back to Idle
      return (to_state == kDeviceStateListening ||
              to_state == kDeviceStateIdle);

    case kDeviceStateListening:
      // Listening can transition to Speaking or back to Idle
      return (to_state == kDeviceStateSpeaking ||
              to_state == kDeviceStateIdle);

    case kDeviceStateSpeaking:
      // Speaking transitions back to Idle
      return to_state == kDeviceStateIdle;

    case kDeviceStateActivating:
      // Activating transitions back to Idle
      return to_state == kDeviceStateIdle;

    case kDeviceStateUpgrading:
      // Upgrading can transition to Idle or FatalError
      return (to_state == kDeviceStateIdle ||
              to_state == kDeviceStateFatalError);

    case kDeviceStateAudioTesting:
      // Audio testing can transition to Idle or FatalError
      return (to_state == kDeviceStateIdle ||
              to_state == kDeviceStateFatalError);

    case kDeviceStateFatalError:
      // FatalError can only transition to itself (stable state)
      return to_state == kDeviceStateFatalError;

    default:
      // All other cases are invalid transitions
      return false;
  }
}

void DeviceStateMachine::TransitionTo(DeviceState target_state) {
    // Step 1: Validate if the transition is allowed
    if (!IsValidTransition(current_state_, target_state)) {
        return; // Invalid transition, do nothing
    }

    // Step 2: Atomically update the current state
    DeviceState old_state = current_state_.exchange(target_state);

    // Step 3: Notify all registered listeners about the state change
    NotifyStateChange(old_state, target_state);
}

int DeviceStateMachine::AddStateChangeListener(StateCallback callback) {
    // Lock the mutex to ensure thread safety when modifying the listeners_ vector
    std::lock_guard<std::mutex> lock(mutex_);

    // Assign a unique ID to the new listener using next_listener_id_
    int listener_id = next_listener_id_;

    // Increment next_listener_id_ for the next listener to ensure uniqueness
    next_listener_id_++;

    // Store the callback with its assigned ID in the listeners_ vector
    listeners_.push_back({listener_id, callback});

    // Return the assigned listener ID so it can be used later for removal
    return listener_id;
}

void DeviceStateMachine::RemoveStateChangeListener(int listener_id) {
    std::lock_guard<std::mutex> lock(listeners_mutex_);

    // Remove the listener with the specified ID
    listeners_.erase(
        std::remove_if(listeners_.begin(), listeners_.end(),
            [listener_id](const std::pair<int, StateCallback>& item) {
                return item.first == listener_id;
            }),
        listeners_.end()
    );
}

void DeviceStateMachine::NotifyStateChange(DeviceState old_state, DeviceState new_state) {
    // Iterate over all registered state change listeners
    for (const auto& listener : listeners_) {
        // Invoke the callback with old and new state
        listener.second(old_state, new_state);
    }
}

