void Ota::Ota()()
{
    // Initialize OTA components
    ota_url_provider_ = std::make_unique<OtaUrlProvider>();
    ota_config_manager_ = std::make_unique<OtaConfigManager>();

    // Get the OTA check version URL from the provider
    std::string check_version_url = ota_url_provider_->GetCheckVersionUrl();

    // Create HTTP client for OTA operations
    HttpClient http_client;

    // Perform version check by sending GET request to the check version URL
    HttpResponse response = http_client.Get(check_version_url);

    // Check if the HTTP request was successful
    if (response.status_code != 200) {
        ESP_LOGE(TAG, "OTA version check failed with status code: %d", response.status_code);
        return;
    }

    // Parse the OTA configuration from the response
    OtaConfig config = ota_config_manager_->ParseOtaConfig(response.body);

    // Apply configuration settings (MQTT, WebSocket, server time)
    ota_config_manager_->ApplyConfig(config);

    // Check if there's a new firmware version available
    if (config.new_version > current_version_) {
        ESP_LOGI(TAG, "New firmware version available: %s", config.new_version.c_str());

        // Download the new firmware
        std::string firmware_url = config.firmware_url;
        std::string firmware_path = "/tmp/firmware.bin";

        if (DownloadFirmware(firmware_url, firmware_path)) {
            // Verify firmware integrity
            if (VerifyFirmware(firmware_path, config.firmware_checksum)) {
                // Start OTA update process
                if (StartOtaUpdate(firmware_path)) {
                    // Mark OTA as successful
                    ota_config_manager_->MarkOtaSuccessful();

                    // Reboot to apply new firmware
                    esp_restart();
                } else {
                    ESP_LOGE(TAG, "OTA update failed");
                    ota_config_manager_->MarkOtaFailed();
                }
            } else {
                ESP_LOGE(TAG, "Firmware verification failed");
                ota_config_manager_->MarkOtaFailed();
            }
        } else {
            ESP_LOGE(TAG, "Firmware download failed");
            ota_config_manager_->MarkOtaFailed();
        }
    } else {
        ESP_LOGI(TAG, "Current firmware version is up to date: %s", current_version_.c_str());
    }

    // Build system info JSON including OTA partition information
    std::string system_info_json = Board::GetSystemInfoJson();

    // Send system info to server for monitoring/debugging purposes
    std::string system_info_url = ota_url_provider_->GetSystemInfoUrl();
    http_client.Post(system_info_url, system_info_json);
}

std::string Ota::GetCheckVersionUrl() {
    // Get the base URL from configuration or environment
    std::string baseUrl = "https://ota.example.com/api/v1/firmware";

    // Get device identifier from board instance
    auto board = Board::GetInstance();
    if (board) {
        // Try to get MAC address or device ID
        std::string deviceId = board->GetMacAddress();
        if (deviceId.empty()) {
            deviceId = board->GetDeviceId();
        }

        // Construct full URL with device identifier
        if (!deviceId.empty()) {
            // Ensure we have at least 10 characters in the final URL
            if (baseUrl.length() + deviceId.length() < 10) {
                // Add some padding or use a default identifier
                deviceId += "_default";
            }
            return baseUrl + "/" + deviceId;
        }
    }

    // Fallback to basic URL if no device identifier is available
    return baseUrl;
}

esp_err_t SetupHttp(std::unique_ptr<Http>* http_client) {
    // Validate input parameter
    if (http_client == nullptr) {
        ESP_LOGE("ota", "Invalid parameter: http_client is null");
        return ESP_ERR_INVALID_ARG;
    }

    // Get network instance from board
    auto& board = Board::GetInstance();
    auto network = board.GetNetwork();

    if (network == nullptr) {
        ESP_LOGE("ota", "Failed to get network instance");
        return ESP_FAIL;
    }

    // Create HTTP client instance
    *http_client = network->CreateHttp(0);

    if (http_client->get() == nullptr) {
        ESP_LOGE("ota", "Failed to create HTTP client");
        return ESP_FAIL;
    }

    return ESP_OK;
}

esp_err_t CheckVersion() {
    // Get the OTA check version URL
    std::string checkVersionUrl = GetCheckVersionUrl();
    if (checkVersionUrl.empty()) {
        ESP_LOGE("OTA", "Failed to get check version URL");
        return ESP_FAIL;
    }

    // Setup HTTP client with required headers
    esp_http_client_handle_t http_client = SetupHttp();
    if (!http_client) {
        ESP_LOGE("OTA", "Failed to setup HTTP client");
        return ESP_FAIL;
    }

    // Set the URL for the HTTP GET request
    esp_err_t err = esp_http_client_set_url(http_client, checkVersionUrl.c_str());
    if (err != ESP_OK) {
        ESP_LOGE("OTA", "Failed to set URL: %s", esp_err_to_name(err));
        esp_http_client_cleanup(http_client);
        return err;
    }

    // Perform the HTTP GET request
    err = esp_http_client_perform(http_client);
    if (err != ESP_OK) {
        ESP_LOGE("OTA", "HTTP GET request failed: %s", esp_err_to_name(err));
        esp_http_client_cleanup(http_client);
        return err;
    }

    // Get the HTTP status code
    int status_code = esp_http_client_get_status_code(http_client);
    if (status_code != 200) {
        ESP_LOGE("OTA", "HTTP request failed with status code: %d", status_code);
        esp_http_client_cleanup(http_client);
        return ESP_FAIL;
    }

    // Get the response buffer
    int response_size = esp_http_client_get_content_length(http_client);
    if (response_size <= 0) {
        ESP_LOGE("OTA", "Invalid response size");
        esp_http_client_cleanup(http_client);
        return ESP_FAIL;
    }

    // Allocate buffer for response
    char* response_buffer = new char[response_size + 1];
    if (!response_buffer) {
        ESP_LOGE("OTA", "Failed to allocate memory for response");
        esp_http_client_cleanup(http_client);
        return ESP_FAIL;
    }

    // Read the response data
    int read_len = esp_http_client_read_response(http_client, response_buffer, response_size);
    if (read_len <= 0) {
        ESP_LOGE("OTA", "Failed to read response data");
        delete[] response_buffer;
        esp_http_client_cleanup(http_client);
        return ESP_FAIL;
    }
    response_buffer[read_len] = '\0';

    // Parse the version information from response
    std::string response_str(response_buffer);
    delete[] response_buffer;

    // Extract firmware version and URL using existing helper functions
    std::string firmware_version;
    std::string firmware_url;

    // Assuming response contains version and url in a structured format
    // This would typically parse JSON or other format
    if (!ParseVersion(response_str, firmware_version, firmware_url)) {
        ESP_LOGE("OTA", "Failed to parse version information from response");
        esp_http_client_cleanup(http_client);
        return ESP_FAIL;
    }

    // Check if new version is available
    std::string current_version = "1.0.0"; // This should come from actual current version
    if (IsNewVersionAvailable(current_version, firmware_version)) {
        ESP_LOGI("OTA", "New version available: %s", firmware_version.c_str());

        // Store the new firmware details for download
        OtaVersionManager& version_manager = OtaVersionManager::GetInstance();
        version_manager.SetNewFirmwareVersion(firmware_version);
        version_manager.SetNewFirmwareUrl(firmware_url);

        // Cleanup HTTP client before returning success
        esp_http_client_cleanup(http_client);
        return ESP_OK;
    } else {
        ESP_LOGI("OTA", "No new version available. Current version: %s", current_version.c_str());
        // Cleanup HTTP client
        esp_http_client_cleanup(http_client);
        return ESP_OK;
    }
}

