int Upgrade(const std::string& firmware_url, std::function<void(int progress, size_t speed)> progress_callback) {
    esp_err_t err;
    esp_ota_handle_t ota_handle = 0;
    const esp_partition_t* next_update_partition = NULL;

    // Validate the update partition
    err = ValidateUpdatePartition();
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to validate update partition: %s", esp_err_to_name(err));
        return err;
    }

    // Get the next available OTA partition
    next_update_partition = esp_ota_get_next_update_partition(NULL);
    if (next_update_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get next update partition");
        return ESP_FAIL;
    }

    // Start OTA update process
    err = esp_ota_begin(next_update_partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed: %s", esp_err_to_name(err));
        return err;
    }

    // Download and write firmware
    err = DownloadAndWriteFirmware(firmware_url, ota_handle, progress_callback);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to download and write firmware: %s", esp_err_to_name(err));
        esp_ota_abort(ota_handle);
        return err;
    }

    // Finalize the OTA update
    err = FinalizeOtaUpdate(ota_handle, next_update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to finalize OTA update: %s", esp_err_to_name(err));
        return err;
    }

    ESP_LOGI(TAG, "OTA update completed successfully");
    return ESP_OK;
}

std::vector<int> Ota::ParseVersion(const std::string &version_str) {
    std::vector<int> version_components;

    // Handle empty string case
    if (version_str.empty()) {
        return version_components;
    }

    // Split the version string by '.'
    size_t start = 0;
    size_t end = 0;

    while ((end = version_str.find('.', start)) != std::string::npos) {
        std::string component = version_str.substr(start, end - start);

        // Convert component to integer and add to vector
        try {
            int num = std::stoi(component);
            version_components.push_back(num);
        } catch (const std::exception&) {
            // If conversion fails, return empty vector to indicate error
            return std::vector<int>();
        }

        start = end + 1;
    }

    // Handle the last component
    std::string last_component = version_str.substr(start);
    if (!last_component.empty()) {
        try {
            int num = std::stoi(last_component);
            version_components.push_back(num);
        } catch (const std::exception&) {
            // If conversion fails, return empty vector to indicate error
            return std::vector<int>();
        }
    }

    return version_components;
}

bool IsNewVersionAvailable(const std::string &currentVersion, const std::string &newVersion)
{
    // Parse both version strings into vectors of integers
    std::vector<int> currentVersionParts = ParseVersion(currentVersion);
    std::vector<int> newVersionParts = ParseVersion(newVersion);

    // Compare the version vectors lexicographically
    // If newVersionParts is greater than currentVersionParts, return true
    return newVersionParts > currentVersionParts;
}

std::string OtaActivationManager::GetActivationPayload() {
    // Create JSON object with activation payload
    JsonObject payload;

    // Add activation challenge (received from server during version check)
    if (!activation_challenge_.empty()) {
        payload["challenge"] = activation_challenge_;
    }

    // Add activation message if available
    if (!activation_message_.empty()) {
        payload["message"] = activation_message_;
    }

    // Add activation code if available
    if (!activation_code_.empty()) {
        payload["code"] = activation_code_;
    }

    // Add timeout information if available
    if (activation_timeout_ms_ > 0) {
        payload["timeout_ms"] = activation_timeout_ms_;
    }

    // Add system information (common in activation payloads)
    payload["system_info"] = GetSystemInfoJson();

    // Convert to JSON string
    std::string json_string;
    payload.ToString(&json_string);

    return json_string;
}

esp_err_t Ota::Activate() {
    // Check if we have the required activation data
    if (!has_serial_number_) {
        ESP_LOGE(TAG, "Missing serial number for activation");
        return ESP_ERR_INVALID_STATE;
    }

    if (!has_activation_challenge_) {
        ESP_LOGE(TAG, "Missing activation challenge for activation");
        return ESP_ERR_INVALID_STATE;
    }

    // Get the activation payload
    std::string payload = GetActivationPayload();
    if (payload.empty()) {
        ESP_LOGE(TAG, "Failed to generate activation payload");
        return ESP_ERR_INVALID_RESPONSE;
    }

    // Setup HTTP client
    esp_http_client_config_t config = {
        .url = ota_server_url_.c_str(),
        .method = HTTP_METHOD_POST,
        .timeout_ms = activation_timeout_ms_,
        .disable_auto_redirect = false,
        .max_redirection_count = 3,
    };

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == NULL) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return ESP_FAIL;
    }

    // Set headers
    esp_http_client_set_header(client, "Content-Type", "application/json");
    esp_http_client_set_header(client, "Accept", "application/json");

    // Set request body
    esp_err_t err = esp_http_client_set_post_field(client, payload.c_str(), payload.length());
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set POST field: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return err;
    }

    // Perform the HTTP request with retry logic
    int retry_count = 0;
    const int max_retries = 3;
    esp_err_t result = ESP_FAIL;

    while (retry_count < max_retries) {
        ESP_LOGI(TAG, "Attempting activation request (attempt %d/%d)", retry_count + 1, max_retries);

        err = esp_http_client_perform(client);
        if (err == ESP_OK) {
            int status_code = esp_http_client_get_status_code(client);
            if (status_code == 200 || status_code == 201) {
                ESP_LOGI(TAG, "Activation successful with status code: %d", status_code);
                result = ESP_OK;
                break;
            } else {
                ESP_LOGW(TAG, "Activation failed with status code: %d", status_code);
                // For certain status codes, we might want to retry
                if (status_code >= 500 && status_code < 600) {
                    retry_count++;
                    vTaskDelay(pdMS_TO_TICKS(1000)); // Wait before retry
                    continue;
                }
            }
        } else {
            ESP_LOGW(TAG, "HTTP request failed: %s", esp_err_to_name(err));
        }

        retry_count++;
        if (retry_count < max_retries) {
            vTaskDelay(pdMS_TO_TICKS(1000)); // Wait before retry
        }
    }

    // Cleanup
    esp_http_client_cleanup(client);

    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Activation failed after %d attempts", max_retries);
        return ESP_ERR_TIMEOUT;
    }

    return ESP_OK;
}

/**
 * Destructor for Settings class
 * Properly closes the NVS handle to release non-volatile storage resources
 */
Settings::~Settings() {
    // Check if the NVS handle is valid before attempting to close it
    if (nvs_handle_ != 0) {
        // Close the NVS handle to release the non-volatile storage
        ESP_ERROR_CHECK(nvs_close(nvs_handle_));
        // Set handle to invalid state after closing
        nvs_handle_ = 0;
    }
}

std::string GetString(const std::string &namespace_name, const std::string &key) {
    // Validate NVS handle
    esp_err_t err = ValidateNVSHandle();
    if (err != ESP_OK) {
        return std::string();
    }

    // First call to nvs_get_str with nullptr to get the required buffer size
    size_t required_size = 0;
    err = nvs_get_str(g_nvs_handle, namespace_name.c_str(), key.c_str(), nullptr, &required_size);

    // If key doesn't exist or other error, return empty string
    if (err != ESP_OK) {
        if (err == ESP_ERR_NVS_NOT_FOUND) {
            return std::string();
        }
        return std::string();
    }

    // If required size is 0, return empty string
    if (required_size == 0) {
        return std::string();
    }

    // Allocate buffer for the string
    char* buffer = new(std::nothrow) char[required_size];
    if (buffer == nullptr) {
        return std::string();
    }

    // Second call to nvs_get_str to actually read the string data
    err = nvs_get_str(g_nvs_handle, namespace_name.c_str(), key.c_str(), buffer, &required_size);
    if (err != ESP_OK) {
        delete[] buffer;
        return std::string();
    }

    // Create string from buffer and trim any trailing null characters
    std::string result(buffer, required_size);

    // Remove trailing null characters that might have been included
    // This is important for proper string handling
    size_t null_pos = result.find('\0');
    if (null_pos != std::string::npos) {
        result = result.substr(0, null_pos);
    }

    delete[] buffer;
    return result;
}

void Settings::SetString(const std::string& key, const std::string& value) {
    // Check if the namespace is opened for writing
    if (!read_write_) {
        return; // Cannot write to read-only namespace
    }

    // Validate the NVS handle
    if (nvs_handle_ == 0) {
        return; // Invalid NVS handle
    }

    // Store the string in NVS
    esp_err_t err = nvs_set_str(nvs_handle_, key.c_str(), value.c_str());
    if (err != ESP_OK) {
        // Handle error appropriately - could throw exception or log error
        return;
    }

    // Set dirty flag to indicate that changes need to be committed
    dirty_ = true;
}

int32_t Settings::GetInt(const std::string &key, int32_t default_value) {
    // Check if NVS handle is valid
    if (nvs_handle_ == 0) {
        return default_value;
    }

    int32_t value = default_value;
    esp_err_t err = nvs_get_i32(nvs_handle_, key.c_str(), &value);

    // Handle different error cases
    if (err == ESP_OK) {
        // Successfully retrieved the value
        return value;
    } else if (err == ESP_ERR_NVS_NOT_FOUND) {
        // Key not found, return default value
        return default_value;
    } else {
        // Other error occurred, return default value
        return default_value;
    }
}

bool Settings::SetInt(const std::string &key, int32_t value) {
    // Check if the settings are in read-write mode
    if (!read_write_) {
        return false;
    }

    // Check if NVS handle is valid
    if (nvs_handle_ == 0) {
        return false;
    }

    // Write the integer value to NVS
    esp_err_t err = nvs_set_i32(nvs_handle_, key.c_str(), value);
    if (err != ESP_OK) {
        return false;
    }

    // Mark that the settings have been modified and need to be committed
    dirty_ = true;

    return true;
}

bool Settings::GetBool(const std::string& key, bool default_value) {
    // Validate NVS handle
    if (nvs_handle_ == 0) {
        return default_value;
    }

    // Attempt to get the boolean value from NVS
    uint8_t value;
    esp_err_t err = nvs_get_u8(nvs_handle_, key.c_str(), &value);

    // If the read operation failed, return the default value
    if (err != ESP_OK) {
        return default_value;
    }

    // Return true if the value is non-zero, false otherwise
    return (value != 0);
}

bool Settings::SetBool(const std::string &key, bool value) {
    // Check if we have write permissions
    if (!read_write_) {
        ESP_LOGW("Settings", "Attempted to write to read-only settings");
        return false;
    }

    // Check if NVS handle is valid
    if (nvs_handle_ == 0) {
        ESP_LOGE("Settings", "NVS handle is invalid");
        return false;
    }

    // Store the boolean value as uint8_t in NVS
    esp_err_t err = nvs_set_u8(nvs_handle_, key.c_str(), value ? 1 : 0);
    if (err != ESP_OK) {
        ESP_LOGE("Settings", "Failed to set bool value for key '%s': %s", 
                 key.c_str(), esp_err_to_name(err));
        return false;
    }

    // Mark the settings as dirty to indicate changes
    dirty_ = true;

    return true;
}

esp_err_t Settings::EraseKey(const std::string &key)
{
    // Validate that NVS handle is valid
    if (nvs_handle_ == 0) {
        ESP_LOGW(TAG, "NVS handle is invalid");
        return ESP_ERR_INVALID_STATE;
    }

    // Check if we have write permission
    if (!read_write_) {
        ESP_LOGW(TAG, "Write permission denied for erasing key: %s", key.c_str());
        return ESP_ERR_NVS_READ_ONLY;
    }

    // Perform the key deletion
    esp_err_t err = nvs_erase_key(nvs_handle_, key.c_str());

    if (err == ESP_OK) {
        ESP_LOGD(TAG, "Successfully erased key: %s", key.c_str());
        return ESP_OK;
    } else if (err == ESP_ERR_NVS_NOT_FOUND) {
        // Key doesn't exist - this is not necessarily an error
        ESP_LOGD(TAG, "Key not found, nothing to erase: %s", key.c_str());
        return ESP_OK;
    } else {
        ESP_LOGE(TAG, "Failed to erase key %s: %s", key.c_str(), esp_err_to_name(err));
        return err;
    }
}

void Settings::EraseAll() {
    // Check if we have read/write permissions
    if (!read_write_) {
        ESP_LOGW(TAG, "Cannot erase all keys: Not in read-write mode");
        return;
    }

    // Use nvs_erase_all to clear all keys in the current namespace
    // This is the standard ESP-IDF approach for clearing entire namespace
    esp_err_t err = nvs_erase_all(handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase all keys in namespace: %s", esp_err_to_name(err));
        return;
    }

    // Mark as dirty to indicate changes need to be committed
    dirty_ = true;

    ESP_LOGI(TAG, "Successfully erased all keys in namespace");
}

int SystemInfo::GetFlashSize() {
    uint32_t flash_size = 0;

    // Get the default flash chip handle
    esp_flash_t* flash_chip = NULL;
    esp_err_t err = esp_flash_get_default_chip(&flash_chip);
    if (err != ESP_OK) {
        ESP_LOGE("SystemInfo", "Failed to get default flash chip: %s", esp_err_to_name(err));
        return -1;
    }

    // Get the flash size
    err = esp_flash_get_size(flash_chip, &flash_size);
    if (err != ESP_OK) {
        ESP_LOGE("SystemInfo", "Failed to get flash size: %s", esp_err_to_name(err));
        return -1;
    }

    ESP_LOGI("SystemInfo", "Flash size: %u bytes (%.2f MB)", flash_size, flash_size / (1024.0f * 1024.0f));

    return (int)flash_size;
}

std::string SystemInfo::GetMacAddress() {
    uint8_t mac[6];

    // Get the default MAC address from EFUSE
    esp_err_t result = esp_efuse_mac_get_default(mac);
    if (result != ESP_OK) {
        // Return empty string or error indicator if reading fails
        return "";
    }

    // Format MAC address as hexadecimal string with colons
    char mac_str[18]; // AA:BB:CC:DD:EE:FF\0
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    return std::string(mac_str);
}

#include <string>
#include <sstream>
#include "system_info.h"
#include "esp_app_format.h"

std::string SystemInfo::GetUserAgent() {
    // Get device MAC address
    std::string mac_address = GetMacAddress();

    // Get chip model name
    std::string chip_model = GetChipModelName();

    // Get application description
    esp_app_desc_t app_desc;
    esp_err_t err = esp_app_get_description(&app_desc);
    if (err != ESP_OK) {
        // Fallback values if unable to retrieve app description
        return "Device/" + chip_model + " App/Unknown/Unknown";
    }

    // Extract relevant fields from app description
    const char* app_name = app_desc.project_name ? app_desc.project_name : "UnknownApp";
    const char* app_version = app_desc.version ? app_desc.version : "UnknownVersion";

    // Build the user agent string
    std::ostringstream ua_stream;
    ua_stream << "Device/" << chip_model
              << " App/" << app_name << "/" << app_version;

    return ua_stream.str();
}

void SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait) {
    // Get the number of tasks
    UBaseType_t uxCurrentNumberOfTasks = uxTaskGetNumberOfTasks();

    // Allocate buffer for task information
    char *pcWriteBuffer = (char *)malloc(uxCurrentNumberOfTasks * 100);
    if (pcWriteBuffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task CPU usage report");
        return;
    }

    // Enable runtime statistics collection
    vTaskGetRunTimeStats(pcWriteBuffer);

    // Log the CPU usage information
    ESP_LOGI(TAG, "Task CPU Usage Statistics:");
    ESP_LOGI(TAG, "%s", pcWriteBuffer);

    // Free allocated memory
    free(pcWriteBuffer);
}

void SystemInfo::PrintTaskList()
{
    UBaseType_t uxArraySize;
    TaskStatus_t *pxTaskStatusArray;
    UBaseType_t uxTaskCount;

    // Get the number of tasks
    uxTaskCount = uxTaskGetNumberOfTasks();

    // Allocate memory for the task status array
    pxTaskStatusArray = (TaskStatus_t *)pvPortMalloc(uxTaskCount * sizeof(TaskStatus_t));

    if (pxTaskStatusArray != NULL)
    {
        // Get the task status information
        uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxTaskCount, NULL);

        // Print header
        printf("Task Name\t\tPriority\tStack High Watermark\n");
        printf("--------------------------------------------------------\n");

        // Print information for each task
        for (UBaseType_t x = 0; x < uxArraySize; x++)
        {
            printf("%-20s\t%-8lu\t%lu\n", 
                   pxTaskStatusArray[x].pcTaskName,
                   pxTaskStatusArray[x].uxCurrentPriority,
                   pxTaskStatusArray[x].usStackHighWaterMark);
        }

        // Free the allocated memory
        vPortFree(pxTaskStatusArray);
    }
    else
    {
        printf("Failed to allocate memory for task list\n");
    }
}

void SystemInfo::PrintHeapStats()
{
    // Get current free heap size
    size_t free_heap_size = esp_get_free_heap_size();

    // Get minimum free heap size since boot
    size_t min_free_heap_size = esp_get_minimum_free_heap_size();

    // Get flash size
    size_t flash_size = 0;
    esp_err_t err = esp_flash_get_size(esp_flash_default_handle(), &flash_size);

    // Convert sizes to KB for better readability
    float free_heap_kb = (float)free_heap_size / 1024.0f;
    float min_free_heap_kb = (float)min_free_heap_size / 1024.0f;
    float flash_size_mb = (float)flash_size / (1024.0f * 1024.0f);

    // Print heap statistics
    printf("\n=== Heap Statistics ===\n");
    printf("Current Free Heap:     %8.1f KB (%zu bytes)\n", free_heap_kb, free_heap_size);
    printf("Minimum Free Heap:     %8.1f KB (%zu bytes)\n", min_free_heap_kb, min_free_heap_size);

    if (err == ESP_OK) {
        printf("Flash Size:            %6.1f MB (%zu bytes)\n", flash_size_mb, flash_size);
    } else {
        printf("Flash Size:            Unable to determine\n");
    }
    printf("======================\n\n");
}

bool AudioCodec::InputData(std::vector<int16_t>& data) {
    if (data.empty()) {
        return false;
    }

    // Calculate number of bytes to read
    size_t num_bytes = data.size() * sizeof(int16_t);

    // Perform I2S read operation
    ssize_t ret = i2s_channel_read(rx_handle_, data.data(), num_bytes, portMAX_DELAY);

    // Check if read was successful
    if (ret < 0) {
        return false;
    }

    return true;
}

void Es8388AudioCodec::Start() {
    // Enable input and output paths to activate the codec
    EnableInput(true);
    EnableOutput(true);
}

void SetOutputVolume(int volume)
{
    // Set the output volume member variable
    output_volume_ = volume;

    // Log the new volume value
    ESP_LOGI("AUDIO_CODEC", "Output volume set to: %d", volume);

    // Persist the volume setting to non-volatile storage
    Settings::GetInstance().SetValue("audio", "output_volume", volume);
}

void Es8388AudioCodec::SetInputGain(float gain)
{
    ESP_LOGI(TAG, "Set input gain to %f", gain);

    // Store the gain value
    input_gain_ = gain;

    // Apply the gain setting to the codec through the control interface
    if (ctrl_if_ != nullptr && input_dev_ != nullptr) {
        // Use the codec's control interface to set the input gain
        // The exact method name may vary based on the esp-codec-dev API
        // Common pattern: ctrl_if_->set_gain(input_dev_, gain);
        // Or potentially: ctrl_if_->set_input_gain(input_dev_, gain);

        // Assuming the standard interface method for setting gain
        esp_err_t ret = ctrl_if_->set_gain(input_dev_, gain);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to set input gain: %d", ret);
        }
    } else {
        ESP_LOGW(TAG, "Codec or input device not initialized");
    }
}

void EnableInput(bool enable) {
    if (rx_handle_ == nullptr) {
        return; // Avoid invalid handle access
    }

    if (enable) {
        i2s_channel_enable(rx_handle_);
    } else {
        i2s_channel_disable(rx_handle_);
    }
}

void AudioCodec::EnableOutput(bool enable) {
    if (enable) {
        ESP_ERROR_CHECK(i2s_channel_enable(tx_handle_));
    } else {
        ESP_ERROR_CHECK(i2s_channel_disable(tx_handle_));
    }
}

Es8388AudioCodec::Es8388AudioCodec(
    void *i2c_master_handle,
    i2c_port_t i2c_port,
    int i2s_port,
    int sample_rate,
    gpio_num_t pa_pin,
    gpio_num_t reset_pin,
    gpio_num_t mute_pin,
    gpio_num_t pdn_pin,
    gpio_num_t clk_pin,
    gpio_num_t ws_pin,
    uint8_t i2c_addr,
    bool use_internal_adc_dac) {

    // Initialize member variables
    i2c_master_handle_ = i2c_master_handle;
    i2c_port_ = i2c_port;
    i2s_port_ = i2s_port;
    sample_rate_ = sample_rate;
    pa_pin_ = pa_pin;
    reset_pin_ = reset_pin;
    mute_pin_ = mute_pin;
    pdn_pin_ = pdn_pin;
    clk_pin_ = clk_pin;
    ws_pin_ = ws_pin;
    i2c_addr_ = i2c_addr;
    use_internal_adc_dac_ = use_internal_adc_dac;

    // Set default values
    input_volume_ = 0;      // -12dB to +30dB range
    output_volume_ = 0;     // -12dB to +30dB range
    input_gain_ = 0;        // 0dB gain
    output_gain_ = 0;       // 0dB gain

    // Initialize I2S channels
    CreateDuplexChannels();

    // Initialize codec device
    codec_dev_.type = AUDIO_CODEC_ES8388_TYPE;
    codec_dev_.i2c_port = i2c_port_;
    codec_dev_.i2c_addr = i2c_addr_;
    codec_dev_.i2c_master_handle = i2c_master_handle_;

    // Initialize GPIO pins
    if (pa_pin_ != GPIO_NUM_NC) {
        gpio_config_t io_conf = {};
        io_conf.pin_bit_mask = (1ULL << pa_pin_);
        io_conf.mode = GPIO_MODE_OUTPUT;
        io_conf.pull_up_en = GPIO_PULLUP_DISABLE;
        io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
        io_conf.intr_type = GPIO_INTR_DISABLE;
        gpio_config(&io_conf);
        gpio_set_level(pa_pin_, 0); // Initially off
    }

    if (reset_pin_ != GPIO_NUM_NC) {
        gpio_config_t io_conf = {};
        io_conf.pin_bit_mask = (1ULL << reset_pin_);
        io_conf.mode = GPIO_MODE_OUTPUT;
        io_conf.pull_up_en = GPIO_PULLUP_DISABLE;
        io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
        io_conf.intr_type = GPIO_INTR_DISABLE;
        gpio_config(&io_conf);
        gpio_set_level(reset_pin_, 0); // Reset low
        vTaskDelay(10 / portTICK_PERIOD_MS); // Wait for reset
        gpio_set_level(reset_pin_, 1); // Release reset
    }

    if (mute_pin_ != GPIO_NUM_NC) {
        gpio_config_t io_conf = {};
        io_conf.pin_bit_mask = (1ULL << mute_pin_);
        io_conf.mode = GPIO_MODE_OUTPUT;
        io_conf.pull_up_en = GPIO_PULLUP_DISABLE;
        io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
        io_conf.intr_type = GPIO_INTR_DISABLE;
        gpio_config(&io_conf);
        gpio_set_level(mute_pin_, 1); // Mute high (active low)
    }

    if (pdn_pin_ != GPIO_NUM_NC) {
        gpio_config_t io_conf = {};
        io_conf.pin_bit_mask = (1ULL << pdn_pin_);
        io_conf.mode = GPIO_MODE_OUTPUT;
        io_conf.pull_up_en = GPIO_PULLUP_DISABLE;
        io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
        io_conf.intr_type = GPIO_INTR_DISABLE;
        gpio_config(&io_conf);
        gpio_set_level(pdn_pin_, 1); // Power down high (active low)
    }

    // Configure I2S pins
    i2s_pin_config_t i2s_pin_config = {
        .mck_io_num = clk_pin_,
        .bck_io_num = GPIO_NUM_NC,  // Not used in standard mode
        .ws_io_num = ws_pin_,
        .data_out_num = GPIO_NUM_NC, // Not used in standard mode
        .data_in_num = GPIO_NUM_NC   // Not used in standard mode
    };

    // Initialize I2S channel
    i2s_channel_config_t i2s_ch_cfg = {
        .id = (i2s_port_ == 0) ? I2S_NUM_0 : I2S_NUM_1,
        .role = I2S_ROLE_MASTER,
        .dma_desc_num = AUDIO_CODEC_DMA_DESC_NUM,
        .dma_frame_num = AUDIO_CODEC_DMA_FRAME_NUM,
        .sample_rate = sample_rate_,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_num = I2S_CHANNEL_STEREO,
        .pin_config = i2s_pin_config
    };

    // Create I2S channel
    i2s_new_channel(&i2s_ch_cfg, &tx_handle_, &rx_handle_);

    // Initialize I2S channel in standard mode
    i2s_channel_init_std_mode(tx_handle_, &i2s_std_cfg_);
    i2s_channel_init_std_mode(rx_handle_, &i2s_std_cfg_);

    // Initialize codec registers
    // Set default volume levels
    Write(ES8388_HPOUTCTRL1, 0x00); // HP_LVOL: 0dB
    Write(ES8388_HPOUTCTRL2, 0x00); // HP_RVOL: 0dB
    Write(ES8388_SPKOUTCTRL1, 0x00); // SPK_LVOL: 0dB
    Write(ES8388_SPKOUTCTRL2, 0x00); // SPK_RVOL: 0dB

    // Set default gain
    Write(ES8388_ADCGAIN, 0x00); // ADC Gain: 0dB
    Write(ES8388_DACGAIN, 0x00); // DAC Gain: 0dB

    // Enable codec
    EnableInput();
    EnableOutput();
}

Es8388AudioCodec::~Es8388AudioCodec() {
    // First, disable I2S channels if they are active
    if (tx_handle_ != nullptr) {
        i2s_channel_disable(tx_handle_);
        tx_handle_ = nullptr;
    }
    if (rx_handle_ != nullptr) {
        i2s_channel_disable(rx_handle_);
        rx_handle_ = nullptr;
    }

    // Close and delete input device if it exists
    if (input_dev_ != nullptr) {
        esp_codec_dev_close(input_dev_);
        esp_codec_dev_delete(input_dev_);
        input_dev_ = nullptr;
    }

    // Close and delete output device if it exists
    if (output_dev_ != nullptr) {
        esp_codec_dev_close(output_dev_);
        esp_codec_dev_delete(output_dev_);
        output_dev_ = nullptr;
    }

    // Delete codec interface if it exists
    if (codec_if_ != nullptr) {
        audio_codec_delete_codec_if(codec_if_);
        codec_if_ = nullptr;
    }

    // Delete control interface if it exists
    if (ctrl_if_ != nullptr) {
        audio_codec_delete_ctrl_if(ctrl_if_);
        ctrl_if_ = nullptr;
    }

    // Delete GPIO interface if it exists
    if (gpio_if_ != nullptr) {
        audio_codec_delete_gpio_if(gpio_if_);
        gpio_if_ = nullptr;
    }

    // Delete data interface if it exists
    if (data_if_ != nullptr) {
        audio_codec_delete_data_if(data_if_);
        data_if_ = nullptr;
    }

    // Explicitly call parent class destructor if needed
    // AudioCodec::~AudioCodec();
}

/**
 * Creates duplex I2S channels for audio codec initialization
 * 
 * This function initializes both transmit and receive I2S channels for full-duplex audio
 * operation. It configures the I2S peripheral with standard mode for TX and TDM mode for RX,
 * using the provided GPIO pins for clock and data signals.
 * 
 * @param mclk Master clock pin number
 * @param bclk Bit clock pin number
 * @param ws Word select (LRCLK) pin number
 * @param dout Digital output pin number
 * @param din Digital input pin number
 * @return esp_err_t ESP_OK on success, error code otherwise
 */
esp_err_t Es8388AudioCodec::CreateDuplexChannels(gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din)
{
    // Assert that input and output sample rates are equal
    assert(input_sample_rate_ == output_sample_rate_);

    // Configure I2S channel for standard mode (TX)
    i2s_chan_config_t chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
    chan_cfg.dma_desc_num = 8;
    chan_cfg.dma_frame_num = 64;
    chan_cfg.flags.use_apll = true;
    chan_cfg.flags.bck_inverted = false;
    chan_cfg.flags.ws_inverted = false;

    // Initialize TX channel
    esp_err_t ret = i2s_new_channel(&chan_cfg, &tx_handle_, NULL);
    if (ret != ESP_OK) {
        return ret;
    }

    // Configure TX channel in standard mode (stereo)
    i2s_std_config_t std_cfg = I2S_STD_CONFIG_DEFAULT(input_sample_rate_, I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO);
    std_cfg.clk_cfg.mclk_freq_hz = input_sample_rate_ * 256;  // MCLK = 256 * sample rate
    std_cfg.clk_cfg.clk_src = I2S_CLK_SRC_APLL;
    std_cfg.slot_cfg.slot_bit_width = I2S_DATA_BIT_WIDTH_16BIT;
    std_cfg.slot_cfg.slot_mode = I2S_SLOT_MODE_STEREO;
    std_cfg.slot_cfg.channel_mask = I2S_STD_SLOT_LEFT | I2S_STD_SLOT_RIGHT;
    std_cfg.gpio_cfg.mclk = mclk;
    std_cfg.gpio_cfg.bclk = bclk;
    std_cfg.gpio_cfg.ws = ws;
    std_cfg.gpio_cfg.dout = dout;
    std_cfg.gpio_cfg.din = I2S_GPIO_NO_CONNECT;
    std_cfg.gpio_cfg.mclk = mclk;

    ret = i2s_channel_init_std_mode(tx_handle_, &std_cfg);
    if (ret != ESP_OK) {
        i2s_del_channel(tx_handle_);
        return ret;
    }

    // Configure RX channel in TDM mode
    i2s_tdm_config_t tdm_cfg = I2S_TDM_CONFIG_DEFAULT();
    tdm_cfg.clk_cfg.mclk_freq_hz = input_sample_rate_ * 256;
    tdm_cfg.clk_cfg.clk_src = I2S_CLK_SRC_APLL;
    tdm_cfg.slot_cfg.slot_bit_width = I2S_DATA_BIT_WIDTH_16BIT;
    tdm_cfg.slot_cfg.slot_mode = I2S_SLOT_MODE_STEREO;
    tdm_cfg.slot_cfg.channel_mask = I2S_TDM_SLOT0 | I2S_TDM_SLOT1;
    tdm_cfg.slot_cfg.tdm_slot_num = 2;
    tdm_cfg.gpio_cfg.mclk = mclk;
    tdm_cfg.gpio_cfg.bclk = bclk;
    tdm_cfg.gpio_cfg.ws = ws;
    tdm_cfg.gpio_cfg.dout = I2S_GPIO_NO_CONNECT;
    tdm_cfg.gpio_cfg.din = din;

    ret = i2s_new_channel(&chan_cfg, NULL, &rx_handle_);
    if (ret != ESP_OK) {
        i2s_del_channel(tx_handle_);
        return ret;
    }

    ret = i2s_channel_init_tdm_mode(rx_handle_, &tdm_cfg);
    if (ret != ESP_OK) {
        i2s_del_channel(tx_handle_);
        i2s_del_channel(rx_handle_);
        return ret;
    }

    return ESP_OK;
}

void Es8388AudioCodec::SetOutputVolume(int volume) {
    // Validate volume range
    if (volume < 0) volume = 0;
    if (volume > 100) volume = 100;

    // Map volume (0-100) to register values
    // ES8388 volume registers typically range from 0x00 (mute) to 0x3F (max)
    // For simplicity, we'll map 0-100 to 0-63 (0x00-0x3F)
    uint8_t reg_value = static_cast<uint8_t>((volume * 63) / 100);

    // Store the volume setting for internal tracking
    output_volume_ = volume;

    // Write to headphone left volume register
    if (ctrl_if_ != nullptr) {
        ctrl_if_->write_reg(HP_LVOL, reg_value);
        // Write to headphone right volume register
        ctrl_if_->write_reg(HP_RVOL, reg_value);
        // Write to speaker left volume register
        ctrl_if_->write_reg(SPK_LVOL, reg_value);
        // Write to speaker right volume register
        ctrl_if_->write_reg(SPK_RVOL, reg_value);
    }
}

bool Es8388AudioCodec::EnableInput(bool enable)
{
    // First, call the parent class method to update internal state
    if (!AudioCodec::EnableInput(enable)) {
        return false;
    }

    // Manage the actual hardware device
    if (enable) {
        // Enable input device
        if (input_dev_ != nullptr) {
            esp_err_t ret = esp_codec_dev_open(input_dev_);
            if (ret != ESP_OK) {
                // Handle error appropriately
                return false;
            }
        }
    } else {
        // Disable input device
        if (input_dev_ != nullptr) {
            esp_err_t ret = esp_codec_dev_close(input_dev_);
            if (ret != ESP_OK) {
                // Handle error appropriately
                return false;
            }
        }
    }

    return true;
}

void Es8388AudioCodec::EnableOutput(bool enable) {
    // Prevent redundant operations if state is already correct
    if (output_enabled_ == enable) {
        return;
    }

    // Lock mutex to ensure thread safety (assuming mutex_ is defined in class)
    std::lock_guard<std::mutex> lock(mutex_);

    if (enable) {
        ESP_LOGI(TAG, "Enabling output");
        esp_err_t err = esp_codec_dev_open(output_dev_);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to open output device: %s", esp_err_to_name(err));
            return;
        }
    } else {
        ESP_LOGI(TAG, "Disabling output");
        esp_err_t err = esp_codec_dev_close(output_dev_);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to close output device: %s", esp_err_to_name(err));
            return;
        }
    }

    // Update internal state and log via base class
    AudioCodec::EnableOutput(enable);
}

int Es8388AudioCodec::Read(int16_t *dest, int samples)
{
    if (!input_enabled_ || !input_dev_) {
        return -1; // Input not enabled or device not open
    }

    size_t bytes_to_read = samples * sizeof(int16_t);
    size_t bytes_read = 0;
    esp_err_t ret = i2s_channel_read(rx_handle_, dest, bytes_to_read, &bytes_read, portMAX_DELAY);

    if (ret != ESP_OK) {
        return -1; // Error occurred while reading
    }

    // Return number of samples read
    return bytes_read / sizeof(int16_t);
}

esp_err_t Es8388AudioCodec::Write(const int16_t *data, int len) {
  if (data == nullptr || len <= 0) {
    return ESP_ERR_INVALID_ARG;
  }

  // Acquire mutex for thread safety
  if (data_if_mutex_ != nullptr) {
    if (xSemaphoreTake(data_if_mutex_, portMAX_DELAY) != pdTRUE) {
      return ESP_FAIL;
    }
  }

  esp_err_t ret = ESP_OK;

  // Check if output is enabled before writing
  if (output_enabled_) {
    // Write audio data to the output device
    ret = esp_codec_dev_write(output_dev_, data, len * sizeof(int16_t));
    if (ret != ESP_OK) {
      ESP_LOGE(TAG, "Failed to write audio data, err: %d", ret);
    }
  } else {
    ESP_LOGW(TAG, "Output not enabled, cannot write audio data");
    ret = ESP_FAIL;
  }

  // Release mutex
  if (data_if_mutex_ != nullptr) {
    xSemaphoreGive(data_if_mutex_);
  }

  return ret;
}

AudioDebugger::AudioDebugger() {
#if CONFIG_USE_AUDIO_DEBUGGER
    // Initialize socket file descriptor to invalid value
    udp_sockfd_ = -1;

    // Clear server address structure
    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));
#endif // CONFIG_USE_AUDIO_DEBUGGER
}

AudioDebugger::~AudioDebugger() {
    // Close the UDP socket if it's open
    if (udp_sockfd_ >= 0) {
        close(udp_sockfd_);
        udp_sockfd_ = -1;
    }

    // Clean up any remaining resources
    // Reset any internal state or flags
    is_running_ = false;

    // If there are any event handlers or callbacks registered,
    // unregister them to prevent dangling pointers
    if (disconnected_callback_) {
        disconnected_callback_ = nullptr;
    }

    // Cleanup any allocated memory or buffers
    // Clear any pending data structures
    audio_buffer_.clear();

    // Notify any listeners about disconnection if needed
    // This follows the pattern seen in Protocol::OnDisconnected
    if (network_event_manager_) {
        network_event_manager_->OnDisconnected();
    }
}

void AudioDebugger::Feed(const std::vector<int16_t>& data) {
#if CONFIG_USE_AUDIO_DEBUGGER
    if (udp_sockfd_ < 0) {
        ESP_LOGW("AUDIO_DEBUGGER", "UDP socket not initialized");
        return;
    }

    if (udp_server_addr_ == nullptr) {
        ESP_LOGW("AUDIO_DEBUGGER", "UDP server address not set");
        return;
    }

    ssize_t sent_bytes = sendto(udp_sockfd_, 
                               data.data(), 
                               data.size() * sizeof(int16_t),
                               0,
                               udp_server_addr_,
                               udp_server_addr_len_);

    if (sent_bytes < 0) {
        ESP_LOGW("AUDIO_DEBUGGER", "Failed to send audio data: %d", errno);
    } else {
        ESP_LOGD("AUDIO_DEBUGGER", "Sent %zd bytes of audio data", sent_bytes);
    }
#endif
}

AfeWakeWord::AfeWakeWord(AudioCodec* codec, srmodel_list_t* model_list)
    : codec_(codec),
      model_list_(model_list),
      event_group_(nullptr),
      detection_task_handle_(nullptr),
      encode_task_handle_(nullptr),
      audio_buffer_(nullptr),
      buffer_size_(0),
      is_initialized_(false),
      is_running_(false) {
    // Initialize the event group for synchronization
    event_group_ = xEventGroupCreate();

    // Initialize other member variables to default values
    memset(&afe_config_, 0, sizeof(afe_config_));
    memset(&pcm_config_, 0, sizeof(pcm_config_));
}

AfeWakeWord::~AfeWakeWord() {
  // Clean up AFE resources if they were initialized
  if (afe_data_ != nullptr && afe_iface_ != nullptr) {
    afe_iface_->destroy(afe_data_);
    afe_data_ = nullptr;
  }

  // Delete the FreeRTOS event group
  if (event_group_ != nullptr) {
    vEventGroupDelete(event_group_);
    event_group_ = nullptr;
  }

  // Clean up the detection task if it was created
  if (wake_word_encode_task_ != nullptr) {
    // Note: vTaskDelete() should be called from the task itself or with proper
    // synchronization. For cleanup, we typically just set the handle to NULL
    // and let the system handle cleanup, or use appropriate task deletion
    wake_word_encode_task_ = nullptr;
  }

  // Free dynamically allocated stack memory
  if (wake_word_encode_task_stack_ != nullptr) {
    vPortFree(wake_word_encode_task_stack_);
    wake_word_encode_task_stack_ = nullptr;
  }

  // Free dynamically allocated buffer memory
  if (wake_word_encode_task_buffer_ != nullptr) {
    vPortFree(wake_word_encode_task_buffer_);
    wake_word_encode_task_buffer_ = nullptr;
  }
}

bool AfeWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    // Validate input parameters
    if (!codec || !models_list) {
        return false;
    }

    // Prepare AFE configuration
    afe_config_t* afe_config = nullptr;

    // Call the setup function that initializes the AFE configuration
    esp_err_t err = SetupAFEConfiguration(codec, models_list, &afe_config);
    if (err != ESP_OK || !afe_config) {
        return false;
    }

    // Create AFE handle and data instance using the configuration
    afe_iface_t* afe_iface = nullptr;
    afe_data_t* afe_data = nullptr;

    err = esp_afe_handle_from_config(afe_config, &afe_iface, &afe_data);
    if (err != ESP_OK || !afe_iface || !afe_data) {
        // Clean up allocated config if needed
        if (afe_config) {
            free(afe_config);
        }
        return false;
    }

    // Assign to class members
    afe_iface_ = afe_iface;
    afe_data_ = afe_data;

    // Free the config after use (assuming it's copied or owned by AFE)
    free(afe_config);

    return true;
}

void AfeWakeWord::Stop() {
    // Clear the DETECTION_RUNNING_EVENT bit to stop the audio detection task
    // This will cause AudioDetectionTask to wake up from its wait and exit gracefully
    xEventGroupClearBits(detection_event_group_, DETECTION_RUNNING_EVENT);

    // Optionally, we could also ensure the task is properly synchronized
    // by waiting for the task to actually stop if needed, but since the task
    // will exit naturally when the event bit is cleared, this is usually sufficient

    // Note: The actual stopping of the detection task happens in AudioDetectionTask()
    // when it wakes up due to the cleared event bit and exits its wait loop
}

bool AfeWakeWord::Feed(const std::vector<int16_t>& data) {
  // Check if afe_data_ is valid before proceeding
  if (afe_data_ == nullptr) {
    return false;
  }

  // Feed the data to the AFE interface
  // The data pointer is passed directly from the vector's internal buffer
  return afe_iface_->feed(afe_data_, data.data());
}

int AfeWakeWord::GetFeedSize() {
    // Check if afe_data_ is valid before proceeding
    if (afe_data_ == nullptr) {
        return 0;
    }

    // Call the AFE interface method to get the feed chunk size
    // This returns the number of audio samples needed per feed operation
    return afe_iface_->get_feed_chunksize(afe_data_);
}

void AudioDetectionTask(void *pvParameters) {
    // Infinite loop to process wake word detection
    while (true) {
        // Wait until the detection is running (i.e., DETECTION_RUNNING_EVENT is set)
        EventBits_t uxBits = xEventGroupWaitBits(
            event_group_,
            DETECTION_RUNNING_EVENT,
            pdFALSE,   // Do not clear bits before returning
            pdTRUE,    // Wait for all bits to be set
            portMAX_DELAY); // Block indefinitely until the event occurs

        // Check if the detection has been started
        if (uxBits & DETECTION_RUNNING_EVENT) {
            // Perform actual wake word detection (assuming afe_iface_ provides this interface)
            bool detected = afe_iface_->detect();

            if (detected) {
                // Store the latest audio data (approx. 2 seconds worth)
                StoreWakeWordData(wake_word_pcm_.data(), wake_word_pcm_.size());

                // Asynchronously encode the stored PCM data to Opus format
                EncodeWakeWordData();

                // Notify upper layers that a wake word was detected
                if (wake_word_detected_callback_) {
                    wake_word_detected_callback_();
                }
            }
        }

        // Small delay to prevent excessive CPU usage
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

void StoreWakeWordData(const int16_t* data, size_t samples) {
    // Validate input parameters
    if (data == nullptr || samples == 0) {
        return;
    }

    // Lock the mutex to ensure thread-safe access to wake_word_pcm_
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Reserve space if needed to avoid multiple reallocations
    wake_word_pcm_.reserve(wake_word_pcm_.size() + samples);

    // Copy the PCM data into the deque
    wake_word_pcm_.insert(wake_word_pcm_.end(), data, data + samples);
}

void EspWakeWord::EncodeWakeWordData() {
    // Lock the mutex to protect access to shared PCM and OPUS buffers
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Check if there is any PCM data to encode
    if (wake_word_pcm_.empty()) {
        return;
    }

    // Concatenate all PCM chunks into one continuous buffer
    std::vector<int16_t> pcm_buffer;
    size_t total_samples = 0;

    for (const auto& chunk : wake_word_pcm_) {
        total_samples += chunk.size();
        pcm_buffer.insert(pcm_buffer.end(), chunk.begin(), chunk.end());
    }

    // Prepare OPUS output buffer
    const int opus_frame_size = 960; // Standard frame size for 48kHz/20ms
    const int max_opus_bytes = 1024; // Max bytes per OPUS packet
    std::vector<uint8_t> opus_buffer(max_opus_bytes);

    // Initialize Opus encoder (assuming opus_encoder_ is initialized)
    int opus_error = 0;

    // Encode the entire PCM buffer into OPUS packets
    int encoded_bytes = opus_encode(opus_encoder_, pcm_buffer.data(), static_cast<int>(total_samples),
                                    opus_buffer.data(), static_cast<int>(opus_buffer.size()));

    if (encoded_bytes < 0) {
        // Handle error case
        ESP_LOGE("WakeWord", "Opus encoding failed with error: %d", encoded_bytes);
        return;
    }

    // Store the encoded OPUS data
    std::vector<uint8_t> encoded_data(opus_buffer.begin(), opus_buffer.begin() + encoded_bytes);
    wake_word_opus_.push_back(std::move(encoded_data));

    // Clear the PCM buffer after processing
    wake_word_pcm_.clear();

    // Notify waiting consumers that new OPUS data is available
    wake_word_cv_.notify_all();
}

bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus_data) {
  std::unique_lock<std::mutex> lock(wake_word_mutex_);

  // Wait until there's data available
  wake_word_cv_.wait(lock, [this] { return !wake_word_opus_.empty(); });

  if (wake_word_opus_.empty()) {
    return false;
  }

  // Retrieve the first OPUS packet
  opus_data = std::move(wake_word_opus_.front());
  wake_word_opus_.pop_front();

  return true;
}

