void CustomWakeWord::ParseWakenetModelConfig() {
    if (models_ == nullptr) {
        return;
    }

    // Clear existing commands
    commands_.clear();

    // Iterate through all model names to find multinet models
    for (int i = 0; i < models_->num_models; i++) {
        const char* model_name = models_->model_name[i];

        // Check if this is a multinet model (has ESP_MN_PREFIX)
        if (model_name != nullptr && strncmp(model_name, ESP_MN_PREFIX, strlen(ESP_MN_PREFIX)) == 0) {
            // Get wake words from the model
            const char* wake_words_str = esp_srmodel_get_wake_words(model_name);

            if (wake_words_str != nullptr) {
                // Split wake words by semicolon
                char* wake_words_copy = strdup(wake_words_str);
                char* token = strtok(wake_words_copy, ";");

                while (token != nullptr) {
                    // Trim whitespace from the token
                    char* start = token;
                    while (*start == ' ') start++;

                    char* end = start + strlen(start) - 1;
                    while (end > start && (*end == ' ' || *end == '\t')) {
                        *end = '\0';
                        end--;
                    }

                    if (strlen(start) > 0) {
                        // Create command configuration
                        WakeWordCommand cmd;
                        cmd.wake_word = std::string(start);

                        // Set default language if not already set
                        if (language_.empty()) {
                            // Try to extract language from model name or use default
                            const char* lang_start = strstr(model_name, "_");
                            if (lang_start != nullptr) {
                                lang_start++; // Move past underscore
                                const char* lang_end = strchr(lang_start, '_');
                                if (lang_end != nullptr) {
                                    language_ = std::string(lang_start, lang_end - lang_start);
                                } else {
                                    // Try to find language after first underscore
                                    lang_end = strchr(lang_start, '-');
                                    if (lang_end != nullptr) {
                                        language_ = std::string(lang_start, lang_end - lang_start);
                                    } else {
                                        language_ = "en"; // Default to English
                                    }
                                }
                            } else {
                                language_ = "en"; // Default to English
                            }
                        }

                        cmd.language = language_;
                        commands_.push_back(cmd);
                    }

                    token = strtok(nullptr, ";");
                }

                free(wake_words_copy);
            }

            // Set language from model metadata if available
            if (language_.empty()) {
                // Try to extract language from model name pattern
                const char* lang_start = strrchr(model_name, '_');
                if (lang_start != nullptr) {
                    lang_start++; // Move past last underscore
                    if (strlen(lang_start) >= 2) {
                        language_ = std::string(lang_start);
                    }
                }
            }
        }
    }

    // If no language was determined, set default
    if (language_.empty()) {
        language_ = "en";
    }

    // If no commands were found, add a default one
    if (commands_.empty()) {
        WakeWordCommand default_cmd;
        default_cmd.wake_word = "default";
        default_cmd.language = language_;
        commands_.push_back(default_cmd);
    }
}

bool CustomWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    // Store the codec reference
    codec_ = codec;

    // Check if models_list is null, initialize default models
    if (models_list == nullptr) {
        ESP_LOGW(TAG, "models_list is null, initializing default models");
        models_list = esp_srmodel_init("model");
        if (models_list == nullptr) {
            ESP_LOGE(TAG, "Failed to initialize default models");
            return false;
        }
    }

    // Find appropriate multinet model based on language and fallback behavior
    srmodel_t* selected_model = esp_srmodel_filter(models_list, ESP_MN_PREFIX, "en", true);
    if (selected_model == nullptr) {
        ESP_LOGE(TAG, "Failed to find suitable multinet model");
        return false;
    }

    // Get multinet handle from model name
    esp_mn_handle_t mn_handle = esp_mn_handle_from_name(selected_model->name);
    if (mn_handle == nullptr) {
        ESP_LOGE(TAG, "Failed to get multinet handle from name: %s", selected_model->name);
        return false;
    }

    // Create multinet instance
    multinet_ = multinet->create(mn_handle, selected_model->path);
    if (multinet_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create multinet instance");
        return false;
    }

    // Set detection threshold
    float threshold = 0.5f; // Default threshold, can be configurable
    if (multinet_->set_det_threshold(threshold) != ESP_OK) {
        ESP_LOGW(TAG, "Failed to set detection threshold");
    }

    // Setup multinet commands
    if (!SetupMultinetCommands(models_list)) {
        ESP_LOGE(TAG, "Failed to setup multinet commands");
        return false;
    }

    // Initialize speech commands
    if (esp_mn_commands_add(multinet_, "wake word", "wake word") != ESP_OK) {
        ESP_LOGE(TAG, "Failed to add wake word command");
        return false;
    }

    // Update commands
    if (esp_mn_commands_update(multinet_) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to update commands");
        return false;
    }

    // Initialize the base WakeWordDetector class
    if (!WakeWordDetector::Initialize(codec, models_list)) {
        ESP_LOGE(TAG, "Failed to initialize base WakeWordDetector");
        return false;
    }

    return true;
}

bool CustomWakeWord::Feed(const std::vector<int16_t>& data) {
    // Validate input data
    if (data.empty()) {
        return false;
    }

    // Store the incoming audio data for potential future use
    StoreWakeWordData(data);

    // Check if we have enough data to feed into the multinet
    if (wake_word_pcm_.size() < static_cast<size_t>(GetFeedSize())) {
        return true; // Not enough data yet, but no error
    }

    // Feed the audio data into the multinet wake word detection engine
    // The esp_mn_feed function expects the audio data in the correct format
    int result = multinet_->feed(wake_word_pcm_.data(), wake_word_pcm_.size());

    if (result != ESP_OK) {
        return false;
    }

    return true;
}

int CustomWakeWord::GetFeedSize() {
    // Get the sample rate from the audio codec
    int sample_rate = codec_->sample_rate();

    // Get the number of input channels
    int channels = codec_->input_channels();

    // Calculate the number of samples for a 30ms window
    // 30ms = 0.03 seconds
    int samples_per_30ms = static_cast<int>(sample_rate * 0.03);

    // Return the number of int16_t samples needed per feed cycle
    // Account for multiple channels by multiplying by number of channels
    return samples_per_30ms * channels;
}

void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t>& data) {
    // Lock the mutex to ensure thread safety when accessing the circular buffer
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Calculate the number of samples in the incoming data
    size_t samples_count = data.size();

    // Check if we need to clear the buffer or add new data
    if (samples_count > wake_word_pcm_.capacity()) {
        // If incoming data is larger than our buffer capacity, 
        // we'll overwrite the entire buffer with new data
        wake_word_pcm_.clear();
        wake_word_pcm_.insert(wake_word_pcm_.end(), data.begin(), data.end());
    } else {
        // Add the new data to the circular buffer
        wake_word_pcm_.insert(wake_word_pcm_.end(), data.begin(), data.end());

        // Maintain the buffer size to approximately 2 seconds of audio data
        // Assuming 16kHz sample rate and 30ms chunks (480 samples per chunk)
        // 2 seconds = 67 chunks * 480 samples = 32160 samples (approximately)
        const size_t max_samples = 32160; // Approximately 2 seconds at 16kHz

        if (wake_word_pcm_.size() > max_samples) {
            // Remove old samples from the beginning to maintain buffer size
            size_t samples_to_remove = wake_word_pcm_.size() - max_samples;
            wake_word_pcm_.erase(wake_word_pcm_.begin(), wake_word_pcm_.begin() + samples_to_remove);
        }
    }

    // Signal that new data is available for encoding
    wake_word_data_available_.notify_one();
}

void CustomWakeWord::EncodeWakeWordData() {
    // Check if there's PCM data to encode
    if (wake_word_pcm_.empty()) {
        return;
    }

    // Get the Opus encoder from the AudioService's OpusCodecHandler
    // This follows the pattern used in OpusCodecTask::ProcessEncodeTask
    auto opus_encoder = audio_service_->GetOpusEncoder();
    if (!opus_encoder) {
        return;
    }

    // Prepare the input PCM data
    const int16_t* pcm_data = wake_word_pcm_.data();
    size_t pcm_size = wake_word_pcm_.size() * sizeof(int16_t);

    // Calculate the maximum output buffer size needed
    // Opus encoder typically requires a reasonable buffer size
    const int max_opus_frame_size = 1024;  // Adjust based on actual requirements
    std::vector<uint8_t> opus_buffer(max_opus_frame_size);

    // Perform the encoding
    int encoded_size = opus_encoder->Encode(
        pcm_data,
        static_cast<int>(wake_word_pcm_.size()),
        opus_buffer.data(),
        static_cast<int>(opus_buffer.size())
    );

    // Check if encoding was successful
    if (encoded_size > 0) {
        // Create a packet structure to hold the encoded data
        // Following the pattern from ProcessEncodeTask
        std::vector<uint8_t> encoded_packet(encoded_size);
        std::copy(opus_buffer.begin(), opus_buffer.begin() + encoded_size, encoded_packet.begin());

        // Thread-safe access to the shared deque
        {
            std::lock_guard<std::mutex> lock(wake_word_opus_mutex_);
            wake_word_opus_.push_back(std::move(encoded_packet));
        }
    }

    // Clear the PCM data after encoding to free memory
    wake_word_pcm_.clear();
}

bool GetWakeWordOpus(std::vector<uint8_t>& opus) {
    // Lock the mutex to ensure thread-safe access to wake_word_opus_
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Check if there is any encoded Opus data available
    if (wake_word_opus_.empty()) {
        return false;
    }

    // Copy the Opus data to the output parameter
    opus = wake_word_opus_;

    // Optionally clear the internal buffer after retrieval
    // wake_word_opus_.clear();

    return true;
}

