void XL9555::SetOutputState(uint8_t bit, uint8_t level)
{
    // Read current output register value to preserve other pin states
    uint8_t current_value = ReadReg(0x07);

    // Create mask for the specific bit
    uint8_t mask = 1 << bit;

    // Set or clear the specific bit based on level
    if (level != 0) {
        // Set the bit to 1
        current_value |= mask;
    } else {
        // Clear the bit to 0
        current_value &= ~mask;
    }

    // Write the modified value back to the register
    WriteReg(0x07, current_value);
}

