FrequencyDetector::FrequencyDetector(float frequency, size_t window_size)
    : frequency_(frequency),
      window_size_(window_size),
      angular_frequency_(2.0f * M_PI * frequency / kSampleRate),
      cos_coefficient_(std::cos(angular_frequency_)),
      sin_coefficient_(std::sin(angular_frequency_)),
      filter_coefficient_(2.0f * cos_coefficient_),
      state_buffer_(2, 0.0f) {
    // Constructor initializes all necessary parameters for Goertzel algorithm
    // The state buffer is initialized with two zeros for the recursive filter
}

void FrequencyDetector::Reset() {
    // Reset the state buffer to initial condition (two zero floats)
    state_buffer_[0] = 0.0f;
    state_buffer_[1] = 0.0f;
}

void FrequencyDetector::ProcessSample(float sample) {
    // Apply the Goertzel algorithm recurrence relation
    // The recurrence relation is: y[n] = cos_coefficient_ * y[n-1] + filter_coefficient_ * y[n-2] + sample

    // Shift the state buffer (circular buffer behavior)
    state_buffer_[1] = state_buffer_[0];
    state_buffer_[0] = sample;

    // Apply Goertzel algorithm formula
    float temp = cos_coefficient_ * state_buffer_[0] + filter_coefficient_ * state_buffer_[1] + sample;

    // Update the internal state for next iteration
    state_buffer_[1] = state_buffer_[0];
    state_buffer_[0] = temp;
}

float FrequencyDetector::GetAmplitude() const {
    // Check if we have enough samples in the state buffer
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Calculate the real and imaginary parts using the Goertzel algorithm
    // The state buffer contains the last three samples: [n-2, n-1, n]
    float real_part = state_buffer_[0] - cos_coefficient_ * state_buffer_[1] + state_buffer_[2];
    float imag_part = sin_coefficient_ * state_buffer_[1] - state_buffer_[2];

    // Calculate the magnitude (amplitude) of the complex number
    // Normalize by half the window size as per Goertzel algorithm convention
    float amplitude = sqrtf(real_part * real_part + imag_part * imag_part) / (window_size_ / 2.0f);

    return amplitude;
}

AudioSignalProcessor::AudioSignalProcessor(size_t sample_rate, size_t mark_frequency, size_t space_frequency, size_t bit_rate, size_t window_size)
    : sample_rate_(sample_rate),
      mark_frequency_(mark_frequency),
      space_frequency_(space_frequency),
      bit_rate_(bit_rate),
      window_size_(window_size),
      input_buffer_size_(sample_rate / bit_rate),
      samples_per_bit_(sample_rate / bit_rate) {

    // Initialize the mark detector with mark frequency and window size
    mark_detector_ = FrequencyDetector(mark_frequency_, window_size_);

    // Initialize the space detector with space frequency and window size
    space_detector_ = FrequencyDetector(space_frequency_, window_size_);
}

std::vector<float> AudioSignalProcessor::ProcessAudioSamples(const std::vector<float> &samples) {
    std::vector<float> probabilities;

    // Process samples in batches of samples_per_bit_
    for (size_t i = 0; i < samples.size(); i += samples_per_bit_) {
        // Ensure we have enough samples for this batch
        if (i + samples_per_bit_ > samples.size()) {
            break;
        }

        // Process each sample in the current batch with both detectors
        for (int j = 0; j < samples_per_bit_; ++j) {
            float sample = samples[i + j];
            mark_detector_.ProcessSample(sample);
            space_detector_.ProcessSample(sample);
        }

        // Calculate amplitudes for both frequencies
        float mark_amplitude = mark_detector_.GetAmplitude();
        float space_amplitude = space_detector_.GetAmplitude();

        // Calculate probability as ratio of mark amplitude to total amplitude
        float total_amplitude = mark_amplitude + space_amplitude;
        float probability = (total_amplitude > 0.0f) ? (mark_amplitude / total_amplitude) : 0.0f;

        // Store the probability for this bit
        probabilities.push_back(probability);

        // Reset detectors for next bit
        mark_detector_.Reset();
        space_detector_.Reset();
    }

    return probabilities;
}

