uint8_t AudioDataBuffer::CalculateChecksum(const std::string &text) {
    uint8_t checksum = 0;
    for (char c : text) {
        checksum += static_cast<uint8_t>(c);
    }
    return checksum;
}

void AudioDataBuffer::ClearBuffers() {
    // Clear the bit buffer which stores received bits
    bit_buffer_.clear();

    // Clear the identifier buffer which stores recent identifier bits
    identifier_buffer_.clear();

    // Reset the decoded text to empty
    decoded_text.reset();
}

