std::vector<uint8_t> AudioDataBuffer::ConvertBitsToBytes(const std::vector<uint8_t>& bits) const {
    std::vector<uint8_t> result;

    // Handle empty input
    if (bits.empty()) {
        return result;
    }

    // Ensure we have complete bytes (multiple of 8 bits)
    size_t complete_bytes = bits.size() / 8;

    // Process each group of 8 bits
    for (size_t i = 0; i < complete_bytes; ++i) {
        uint8_t byte = 0;

        // Pack 8 bits into one byte (MSB first)
        for (int bit_pos = 0; bit_pos < 8; ++bit_pos) {
            // Get the bit at position bit_pos in current byte group
            uint8_t bit_value = bits[i * 8 + bit_pos];

            // Set the corresponding bit in the byte (MSB first)
            byte |= (bit_value << (7 - bit_pos));
        }

        result.push_back(byte);
    }

    return result;
}

