void Backlight::SetBrightness(uint8_t brightness, bool permanent)
{
    // Clamp brightness to valid range [0, 100]
    if (brightness > 100) {
        brightness = 100;
    }

    // Store the target brightness
    target_brightness_ = brightness;

    // If this is a permanent change, save it to settings
    if (permanent) {
        Settings::GetInstance()->SetBacklightBrightness(brightness);
    }

    // If we're already at the target brightness, no animation needed
    if (brightness_ == brightness) {
        return;
    }

    // Determine the direction of change
    if (brightness_ < brightness) {
        step_ = 1;  // Increasing brightness
    } else {
        step_ = -1; // Decreasing brightness
    }

    // Update the current brightness immediately
    brightness_ = brightness_;

    // Start the transition timer if not already running
    if (!transition_timer_.IsRunning()) {
        transition_timer_.Start();
    }

    // Perform the hardware-specific brightness update
    SetBrightnessImpl(brightness);
}

void Backlight::OnTransitionTimer() {
    // Check if we've reached the target brightness
    if (brightness_ == target_brightness_) {
        // Stop the timer since transition is complete
        esp_timer_stop(transition_timer_);
        return;
    }

    // Update brightness based on step direction
    brightness_ += step_;

    // Apply the updated brightness to hardware
    SetBrightnessImpl(brightness_);
}

