std::string GenerateUuid() {
    // Get MAC address for hardware uniqueness
    std::string macAddress = SystemInfo::GetMacAddress();

    // Convert MAC address to bytes for seeding random generator
    uint32_t seed = 0;
    if (!macAddress.empty()) {
        // Simple hash of MAC address for seeding
        for (size_t i = 0; i < macAddress.length() && i < 4; ++i) {
            seed ^= (static_cast<uint32_t>(macAddress[i]) << (i * 8));
        }
    }

    // Seed the random number generator with MAC-derived value
    srand(seed);

    // Generate UUID version 4 (random)
    // Format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    std::stringstream uuid;

    // First 8 characters
    for (int i = 0; i < 8; ++i) {
        uuid << std::hex << std::setfill('0') << std::setw(2) 
             << (rand() & 0xFF);
    }

    uuid << "-";

    // Next 4 characters
    for (int i = 0; i < 4; ++i) {
        uuid << std::hex << std::setfill('0') << std::setw(2) 
             << (rand() & 0xFF);
    }

    uuid << "-4";

    // Next 3 characters (version 4)
    for (int i = 0; i < 3; ++i) {
        uuid << std::hex << std::setfill('0') << std::setw(2) 
             << (rand() & 0xFF);
    }

    uuid << "-";

    // Next 4 characters (variant bits)
    uint8_t variant = (rand() & 0x3F) | 0x80;  // Set variant bits
    uuid << std::hex << std::setfill('0') << std::setw(2) << static_cast<int>(variant);

    // Next 11 characters
    for (int i = 0; i < 11; ++i) {
        uuid << std::hex << std::setfill('0') << std::setw(2) 
             << (rand() & 0xFF);
    }

    return uuid.str();
}

