/**
 * @brief Generates a JSON string containing system information
 * @return cJSON* pointer to the constructed JSON object
 */
cJSON* GetSystemInfoJson() {
    // Create the root JSON object
    cJSON* root = cJSON_CreateObject();
    if (root == NULL) {
        return NULL;
    }

    // Get system information using SystemInfo class methods
    const char* chip_model = SystemInfo::GetChipModelName();
    const char* mac_address = SystemInfo::GetMacAddress();
    const char* user_agent = SystemInfo::GetUserAgent();
    uint32_t flash_size = SystemInfo::GetFlashSize();

    // Get UUID from Board class
    const char* uuid = Board::GetInstance()->GetUuid();

    // Add system information to JSON object
    if (chip_model != NULL) {
        cJSON_AddStringToObject(root, "chip_model", chip_model);
    }

    if (mac_address != NULL) {
        cJSON_AddStringToObject(root, "mac_address", mac_address);
    }

    if (user_agent != NULL) {
        cJSON_AddStringToObject(root, "user_agent", user_agent);
    }

    // Add flash size as integer
    cJSON_AddNumberToObject(root, "flash_size", flash_size);

    // Add UUID
    if (uuid != NULL) {
        cJSON_AddStringToObject(root, "uuid", uuid);
    }

    // Add board type information
    const char* board_type = Board::GetInstance()->GetBoardType();
    if (board_type != NULL) {
        cJSON_AddStringToObject(root, "board_type", board_type);
    }

    return root;
}

