void WifiBoard::StartNetwork() {
    // Check if there are any configured SSIDs available
    auto ssidList = SsidManager::GetInstance().GetSsidList();

    // If no SSIDs are configured, start WiFi configuration mode
    if (ssidList.empty()) {
        StartWifiConfigMode();
        return;
    }

    // Attempt to connect to WiFi network
    TryWifiConnect();
}

void WifiBoard::TryWifiConnect() {
    // Start the connection timeout timer
    if (connect_timeout_timer_ != nullptr) {
        esp_timer_stop(connect_timeout_timer_);
        esp_timer_start_once(connect_timeout_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
    }

    // Attempt to connect to the previously saved WiFi network
    // This assumes WifiManager has a Connect method that takes SSID and password
    // or uses stored credentials from previous configuration

    // Check if we have saved credentials or need to scan for networks
    if (wifi_manager_.IsConnected()) {
        // Already connected, stop the timer
        if (connect_timeout_timer_ != nullptr) {
            esp_timer_stop(connect_timeout_timer_);
        }
        return;
    }

    // Try to connect using the saved configuration
    // This would typically use the WifiManager's connect method with stored credentials
    wifi_manager_.Connect();
}

