    // Cast the argument back to WifiBoard instance
    WifiBoard* wifi_board = static_cast<WifiBoard*>(arg);

    // Log warning about WiFi connection timeout
    ESP_LOGW(TAG, "WiFi connection timeout occurred");

    // Stop the current station connection attempt
    WifiManager::GetInstance()->StopStation();

    // Transition to Wi-Fi configuration mode
    wifi_board->StartWifiConfigMode();
}

void StartWifiConfigMode() {
    // Stop any ongoing station connection attempts
    esp_timer_stop(wifi_connect_timer);
    WifiManager::StopStation();

    // Clear any existing connection attempts
    WifiManager::ClearPendingConnections();

#if CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Handle BLUFI provisioning if enabled
    if (blufi_handler != nullptr) {
        // Disconnect BLUFI if currently connected
        esp_blufi_disconnect();
        // Reset BLUFI handler state
        blufi_handler->Reset();
    }
#endif

    // Start WiFi in configuration AP mode
    WifiManager::StartConfigAp();

    // Set the device state to configuration mode
    wifi_board.SetInWifiConfigMode(true);

    // Log that we've entered configuration mode
    ESP_LOGI(TAG, "Entered WiFi Configuration Mode");
}

void WifiBoard::EnterWifiConfigMode() {
    // Set device state to indicate wifi configuration is in progress
    Application::GetInstance().SetDeviceState(kDeviceStateWifiConfiguring);

    // Start hotspot provisioning if enabled
    #if CONFIG_USE_HOTSPOT_WIFI_PROVISIONING
    WifiManager::GetInstance().StartConfigAp();
    #endif

    // Initialize BLUFI provisioning if enabled
    #if CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    Blufi::init();
    #endif

    // Start acoustic provisioning if enabled
    #if CONFIG_USE_ACOUSTIC_WIFI_PROVISIONING
    // Get audio codec instance for acoustic provisioning
    auto* audio_codec = Board::GetInstance().GetAudioCodec();
    if (audio_codec != nullptr) {
        // Schedule the audio-based wifi configuration
        Application::GetInstance().Schedule([audio_codec]() {
            audio_wifi_config::ReceiveWifiCredentialsFromAudio();
        });
    }
    #endif
}

