const char* WifiBoard::GetNetworkStateIcon() {
    WifiManager& wifi = WifiManager::GetInstance();

    // Check if we're in configuration mode first
    if (wifi.IsConfigMode()) {
        return "";  // WiFi icon for configuration mode
    }

    // Check connection status
    switch (wifi.GetConnectionStatus()) {
        case WIFI_CONNECTED:
            // For connected state, we can also consider signal strength
            {
                int rssi = wifi.GetRssi();
                if (rssi >= -50) {
                    return "";  // Full signal strength
                } else if (rssi >= -70) {
                    return "";  // Good signal strength
                } else if (rssi >= -80) {
                    return "";  // Medium signal strength
                } else {
                    return "";  // Weak signal strength
                }
            }
        case WIFI_CONNECTING:
            return "";  // WiFi icon for connecting state
        case WIFI_DISCONNECTED:
            return "";  // WiFi slash or disconnected icon
        default:
            return "";  // Default WiFi icon
    }
}

