void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level)
{
    // Configure ESP-IDF power save mode based on the requested level
    esp_err_t result = ESP_OK;

    switch (level) {
        case PowerSaveLevel::NONE:
            // Disable power save - full performance mode
            result = esp_wifi_set_ps(ESP_WIFI_PS_NONE);
            if (result == ESP_OK) {
                // Disable power save timer
                if (powerSaveTimer != nullptr) {
                    powerSaveTimer->SetEnabled(false);
                }
            }
            break;

        case PowerSaveLevel::LIGHT_SLEEP:
            // Enable light sleep power save
            result = esp_wifi_set_ps(ESP_WIFI_PS_MIN_MODEM);
            if (result == ESP_OK) {
                // Enable power save timer with appropriate settings
                if (powerSaveTimer != nullptr) {
                    powerSaveTimer->SetEnabled(true);
                }
            }
            break;

        case PowerSaveLevel::DEEP_SLEEP:
            // Enable deep sleep power save
            result = esp_wifi_set_ps(ESP_WIFI_PS_MAX_MODEM);
            if (result == ESP_OK) {
                // Enable power save timer with deep sleep settings
                if (powerSaveTimer != nullptr) {
                    powerSaveTimer->SetEnabled(true);
                }
            }
            break;

        default:
            // Handle unknown power save level
            result = ESP_ERR_INVALID_ARG;
            break;
    }

    // If we have a Settings object, update it with the new power save level
    if (settings != nullptr) {
        settings->SetPowerSaveLevel(level);
    }

    // Handle error cases
    if (result != ESP_OK) {
        // Log error or handle appropriately based on system requirements
        // For now, we'll just return as the function signature doesn't indicate error handling
    }
}

