void OledDisplay::SetChatMessage(const char* role, const char* content) {
    // Acquire display lock to ensure thread safety when updating UI
    DisplayLockGuard lock(display_mutex_);

    // Handle null pointer cases
    if (role == nullptr || content == nullptr) {
        return;
    }

    // Create a copy of content to modify (replace newlines with spaces)
    std::string modified_content = content;

    // Replace newline characters with spaces for proper rendering
    size_t pos = 0;
    while ((pos = modified_content.find('\n', pos)) != std::string::npos) {
        modified_content.replace(pos, 1, " ");
        pos++;
    }

    // Update the main chat message label with the role and content
    lv_label_set_text_fmt(chat_message_label_, "%s: %s", role, modified_content.c_str());

    // Check if we have a secondary content object (content_right_)
    if (content_right_ != nullptr) {
        // If content is empty, hide the secondary label
        if (modified_content.empty()) {
            lv_obj_add_flag(content_right_, LV_OBJ_FLAG_HIDDEN);
        } else {
            // Otherwise show the secondary label
            lv_obj_remove_flag(content_right_, LV_OBJ_FLAG_HIDDEN);
        }
    }

    // Ensure the main chat message label is visible
    lv_obj_remove_flag(chat_message_label_, LV_OBJ_FLAG_HIDDEN);
}

