SingleLed::~SingleLed() {
    // Stop the blink timer to prevent further timer callbacks
    if (blink_timer_) {
        esp_timer_stop(blink_timer_);
        // Delete the timer handle to free resources
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
    }

    // Delete the LED strip handle to free allocated resources
    if (led_strip_) {
        led_strip_del(led_strip_);
        led_strip_ = nullptr;
    }
}

void SingleLed::SetColor(uint8_t r, uint8_t g, uint8_t b) {
    // Acquire mutex to ensure thread safety when modifying shared state
    std::lock_guard<std::mutex> lock(mutex_);

    // Store the provided RGB values in member variables
    r_ = r;
    g_ = g;
    b_ = b;

    // Set the pixel color on the LED strip (index 0 for single LED)
    led_strip_set_pixel(led_strip_, 0, r, g, b);

    // Refresh the LED strip to apply the new color
    led_strip_refresh(led_strip_);
}

void TurnOn() {
    // Set the first pixel (index 0) to the stored RGB color values
    led_strip_set_pixel(led_strip_, 0, r_, g_, b_);

    // Refresh the LED strip to make the color change visible
    led_strip_refresh(led_strip_);
}

void CircularStrip::TurnOff() {
    // Lock mutex for thread safety
    std::lock_guard<std::mutex> lock(mutex_);

    // Stop any ongoing blink task if it exists
    if (blink_timer_handle_ != nullptr) {
        esp_timer_stop(blink_timer_handle_);
        esp_timer_delete(blink_timer_handle_);
        blink_timer_handle_ = nullptr;
    }

    // Clear all LED pixels to turn them off
    led_strip_clear(led_strip_);

    // Refresh the LED strip to apply changes
    led_strip_refresh(led_strip_);
}

void SingleLed::StartBlinkTask(int times, int interval_ms) {
    // Lock the mutex to safely access shared resources
    std::lock_guard<std::mutex> lock(blink_mutex_);

    // Initialize the blink counter based on the number of times
    // Each blink consists of ON and OFF states, so we need twice the number of times
    blink_counter_ = times * 2;

    // If times is 0, we want continuous blinking
    if (times == 0) {
        blink_counter_ = -1; // Special value to indicate continuous blinking
    }

    // Set up the timer configuration
    esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            SingleLed* led = static_cast<SingleLed*>(arg);
            led->OnBlinkTimer();
        },
        .arg = this,
        .name = "blink_timer",
        .skip_unhandled_events = false
    };

    // Create the timer if it doesn't exist
    if (blink_timer_ == nullptr) {
        esp_timer_create(&timer_args, &blink_timer_);
    }

    // Start the timer with the specified interval
    esp_timer_start_periodic(blink_timer_, interval_ms * 1000); // Convert ms to microseconds
}

void SingleLed::OnBlinkTimer() {
    std::lock_guard<std::mutex> lock(mutex_);

    // Toggle the LED state
    if (is_on_) {
        // Turn off the LED
        SetLedState(false);
        is_on_ = false;
    } else {
        // Turn on the LED
        SetLedState(true);
        is_on_ = true;
    }

    // Decrement the blink counter
    blink_counter_--;

    // If all blinks are done, stop the timer
    if (blink_counter_ <= 0) {
        esp_timer_stop(timer_);
    }
}

void SingleLed::OnStateChanged()
{
    DeviceState state = Application::GetInstance().GetDeviceState();

    switch (state)
    {
        case DeviceState::IDLE:
            // Turn LED on with blue color when idle
            TurnOn();
            SetColor(Color::BLUE);
            break;

        case DeviceState::CONNECTING:
            // Blink LED with yellow color when connecting
            Blink(Color::YELLOW, 500);  // 500ms blink interval
            break;

        case DeviceState::LISTENING:
            // Turn LED on with green color when listening
            TurnOn();
            SetColor(Color::GREEN);
            break;

        case DeviceState::SPEAKING:
            // Fast blink with red color when speaking
            Blink(Color::RED, 200);  // 200ms fast blink interval
            break;

        case DeviceState::ERROR:
            // Rapid blink with red color when error occurs
            Blink(Color::RED, 100);  // 100ms very fast blink
            break;

        default:
            // Turn LED off for unknown states
            TurnOff();
            break;
    }
}

