bool MqttProtocol::StartMqttClient(bool report_error) {
  // Early exit if the protocol is no longer active
  if (!alive_) {
    return false;
  }

  // Only attempt connection if the device is in idle state
  if (Application::GetInstance().GetDeviceState() != kDeviceStateIdle) {
    ESP_LOGW(kTag, "Cannot start MQTT client: device is not idle.");
    return false;
  }

  // Attempt to stop any existing MQTT client first
  if (mqtt_) {
    mqtt_->Stop();
    mqtt_.reset();
  }

  // Retrieve MQTT settings from configuration
  auto settings = Settings::GetInstance();
  std::string broker_address = settings->GetString("mqtt.broker_address");
  int port = settings->GetInt("mqtt.port", 1883);
  std::string username = settings->GetString("mqtt.username");
  std::string password = settings->GetString("mqtt.password");
  bool use_tls = settings->GetBool("mqtt.use_tls", false);

  // Create new MQTT client instance
  mqtt_ = std::make_unique<MqttClient>(broker_address, port, username, password, use_tls);

  // Set up callbacks for connection status and messages
  mqtt_->SetOnConnectedCallback([this]() {
    ESP_LOGI(kTag, "MQTT client connected successfully.");
    // Subscribe to necessary topics here
    mqtt_->Subscribe("server/hello", [this](const std::string& payload) {
      // Handle incoming hello message
      ParseServerHello(payload.c_str());
    });
  });

  mqtt_->SetOnDisconnectedCallback([this]() {
    ESP_LOGW(kTag, "MQTT client disconnected.");
    if (alive_) {
      // Reconnect after delay
      Application::GetInstance().Schedule([this]() {
        StartMqttClient(true); // Report error on reconnection failure
      }, kReconnectDelayMs);
    }
  });

  // Try to connect to the broker
  if (!mqtt_->Connect()) {
    ESP_LOGE(kTag, "Failed to connect to MQTT broker.");
    if (report_error) {
      // Optionally report error to UI or log
      Application::GetInstance().NotifyError("MQTT connection failed.");
    }
    return false;
  }

  // Successfully connected; set the event group to indicate readiness
  xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);

  return true;
}

bool SendText(const std::string &text) {
    // Check if MQTT client is available and connected
    if (!mqtt_ || !mqtt_->isConnected()) {
        return false;
    }

    // Check if publish topic is configured
    if (publish_topic_.empty()) {
        return false;
    }

    // Publish the text message to the configured topic
    // Assuming the MQTT client has a publish method that returns bool
    // This follows the pattern of sending JSON messages in OpenAudioChannel()
    try {
        bool result = mqtt_->publish(publish_topic_.c_str(), text.c_str(), text.length());
        return result;
    } catch (...) {
        // Handle any exceptions that might occur during publish
        return false;
    }
}

void MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    if (!udp_) {
        return;
    }

    // Prepare packet header
    uint8_t header[4];
    header[0] = static_cast<uint8_t>(PacketType::AUDIO_STREAM_PACKET);
    header[1] = 0; // Flags (reserved for now)
    header[2] = static_cast<uint8_t>((local_sequence_ >> 8) & 0xFF);
    header[3] = static_cast<uint8_t>(local_sequence_ & 0xFF);

    // Increment sequence number for next packet
    local_sequence_++;

    // Serialize packet data
    std::vector<uint8_t> buffer;
    buffer.reserve(4 + packet->data.size());

    // Add header
    buffer.insert(buffer.end(), header, header + 4);

    // Add payload
    buffer.insert(buffer.end(), packet->data.begin(), packet->data.end());

    // Send packet over UDP
    udp_->Send(buffer.data(), buffer.size());
}

void MqttProtocol::CloseAudioChannel() {
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Check if audio channel is already closed
    if (!is_audio_channel_open_) {
        return;
    }

    // Close UDP connection if it exists
    if (udp_ && udp_->IsOpen()) {
        udp_->Close();
    }

    // Reset session ID and other audio-related state
    session_id_ = 0;
    sequence_number_ = 0;
    is_audio_channel_open_ = false;

    // Clear any pending audio events
    ClearEvent(MQTT_PROTOCOL_SERVER_HELLO_EVENT);

    // Notify listeners that audio channel is closed
    if (on_audio_channel_closed_) {
        on_audio_channel_closed_();
    }
}

bool MqttProtocol::OpenAudioChannel() {
    // Generate the hello message for MQTT protocol
    std::string hello_message = GetHelloMessage();

    // Send hello message to server via MQTT
    if (!SendHelloMessage(hello_message)) {
        return false;
    }

    // Wait for server hello response
    if (!WaitForServerHello()) {
        return false;
    }

    // Parse server hello to extract UDP configuration
    if (!ParseServerHello()) {
        return false;
    }

    // Create and configure UDP socket
    udp_socket_ = socket(AF_INET, SOCK_DGRAM, 0);
    if (udp_socket_ < 0) {
        return false;
    }

    // Configure UDP socket with server settings
    struct sockaddr_in server_addr;
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(udp_port_);
    server_addr.sin_addr.s_addr = inet_addr(udp_server_.c_str());

    // Set socket options for better performance
    int buffer_size = 65536; // 64KB buffer
    setsockopt(udp_socket_, SOL_SOCKET, SO_RCVBUF, &buffer_size, sizeof(buffer_size));

    // Bind socket to local address
    struct sockaddr_in local_addr;
    memset(&local_addr, 0, sizeof(local_addr));
    local_addr.sin_family = AF_INET;
    local_addr.sin_addr.s_addr = INADDR_ANY;
    local_addr.sin_port = 0; // Let OS choose port

    if (bind(udp_socket_, (struct sockaddr*)&local_addr, sizeof(local_addr)) < 0) {
        close(udp_socket_);
        udp_socket_ = -1;
        return false;
    }

    // Initialize AES context with server-provided key
    if (AES_set_decrypt_key((unsigned char*)aes_key_.data(), 128, &aes_ctx_) < 0) {
        close(udp_socket_);
        udp_socket_ = -1;
        return false;
    }

    // Set up callback for incoming audio packets
    // This would typically involve setting up a thread or event loop
    // to handle incoming UDP packets

    // Signal successful completion
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);

    return true;
}

std::string GetHelloMessage() {
    // Create the root JSON object
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        return "";
    }

    // Add type field
    cJSON_AddStringToObject(root, "type", "hello");

    // Add version field
    cJSON_AddNumberToObject(root, "version", 1);

    // Add features object
    cJSON* features = cJSON_CreateObject();
    if (features) {
        // Add AEC feature based on configuration
#ifdef CONFIG_USE_SERVER_AEC
        cJSON_AddTrueToObject(features, "aec");
#else
        cJSON_AddFalseToObject(features, "aec");
#endif
        // Add MCP feature (assuming it's always available or configurable)
        cJSON_AddTrueToObject(features, "mcp");
        cJSON_AddItemToObject(root, "features", features);
    }

    // Add transport field
    cJSON_AddStringToObject(root, "transport", "mqtt");

    // Add audio_params object
    cJSON* audio_params = cJSON_CreateObject();
    if (audio_params) {
        cJSON_AddStringToObject(audio_params, "format", "pcm");
        cJSON_AddNumberToObject(audio_params, "sample_rate", 16000);
        cJSON_AddNumberToObject(audio_params, "channels", 1);
        cJSON_AddNumberToObject(audio_params, "frame_duration", 20);
        cJSON_AddItemToObject(root, "audio_params", audio_params);
    }

    // Convert to string
    char* json_string = cJSON_PrintUnformatted(root);
    std::string result;

    if (json_string) {
        result = json_string;
        free(json_string);
    }

    // Clean up
    cJSON_Delete(root);

    return result;
}

void MqttProtocol::ParseServerHello(const cJSON* root) {
    // Initialize sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Validate transport field
    const cJSON* transport = cJSON_GetObjectItem(root, "transport");
    if (transport == nullptr || !cJSON_IsString(transport)) {
        // Handle error: missing or invalid transport field
        return;
    }

    if (strcmp(transport->valuestring, "udp") != 0) {
        // Handle error: unsupported transport type
        return;
    }

    // Extract session_id if present
    const cJSON* session_id = cJSON_GetObjectItem(root, "session_id");
    if (session_id != nullptr && cJSON_IsString(session_id)) {
        session_id_ = session_id->valuestring;
    }

    // Parse audio parameters
    const cJSON* audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (audio_params != nullptr && cJSON_IsObject(audio_params)) {
        // Extract sample_rate
        const cJSON* sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (sample_rate != nullptr && cJSON_IsNumber(sample_rate)) {
            audio_sample_rate_ = sample_rate->valuedouble;
        }

        // Extract frame_duration
        const cJSON* frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (frame_duration != nullptr && cJSON_IsNumber(frame_duration)) {
            audio_frame_duration_ = frame_duration->valuedouble;
        }
    }

    // Set the event group bit to signal successful processing
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

char CharToHex(char c) {
    // Helper array for hex character mapping
    const char hex_chars[] = "0123456789ABCDEF";

    // Convert to uppercase for easier comparison
    if (c >= 'a' && c <= 'f') {
        c = c - 'a' + 'A';
    }

    // Find the position of the character in hex_chars array
    for (int i = 0; i < 16; i++) {
        if (hex_chars[i] == c) {
            return static_cast<char>(i);
        }
    }

    // If character is not a valid hex character, return -1 or handle as needed
    // Based on usage context, this should not happen with valid inputs
    return static_cast<char>(-1);
}

std::string DecodeHexString(const std::string &hexString) {
    // Handle empty input
    if (hexString.empty()) {
        return "";
    }

    // Reserve space to avoid repeated reallocations
    std::string result;
    result.reserve(hexString.length() / 2);

    // Process two characters at a time
    for (size_t i = 0; i < hexString.length(); i += 2) {
        // Ensure we have at least two characters left
        if (i + 1 >= hexString.length()) {
            // Invalid hex string (odd number of characters)
            return "";
        }

        // Convert first character to hex value
        char highNibble = hexString[i];
        char lowNibble = hexString[i + 1];

        // Convert hex characters to numeric values
        int highValue = 0;
        int lowValue = 0;

        // Handle uppercase hex characters
        if (highNibble >= '0' && highNibble <= '9') {
            highValue = highNibble - '0';
        } else if (highNibble >= 'A' && highNibble <= 'F') {
            highValue = highNibble - 'A' + 10;
        } else if (highNibble >= 'a' && highNibble <= 'f') {
            highValue = highNibble - 'a' + 10;
        } else {
            // Invalid hex character
            return "";
        }

        // Handle lowercase hex characters
        if (lowNibble >= '0' && lowNibble <= '9') {
            lowValue = lowNibble - '0';
        } else if (lowNibble >= 'A' && lowNibble <= 'F') {
            lowValue = lowNibble - 'A' + 10;
        } else if (lowNibble >= 'a' && lowNibble <= 'f') {
            lowValue = lowNibble - 'a' + 10;
        } else {
            // Invalid hex character
            return "";
        }

        // Combine high and low nibbles into a byte
        unsigned char byteValue = static_cast<unsigned char>((highValue << 4) | lowValue);
        result.push_back(static_cast<char>(byteValue));
    }

    return result;
}

void NetworkEventManager::SetError(const std::string &error_message) {
    // Set the error occurred flag to true
    error_occurred_ = true;

    // Store the error message for potential use
    last_error_message_ = error_message;

    // Notify any registered network error handler if it exists
    if (on_network_error_) {
        on_network_error_(error_message);
    }
}

void Protocol::SendAbortSpeaking(AbortReason reason) {
    // Create JSON object for abort speaking event
    json message;
    message["type"] = "abort_speaking";
    message["session_id"] = session_id_;

    // Convert AbortReason enum to string representation
    switch (reason) {
        case AbortReason::USER_REQUESTED:
            message["reason"] = "user_requested";
            break;
        case AbortReason::TIMEOUT:
            message["reason"] = "timeout";
            break;
        case AbortReason::ERROR:
            message["reason"] = "error";
            break;
        case AbortReason::NETWORK_ERROR:
            message["reason"] = "network_error";
            break;
        default:
            message["reason"] = "unknown";
            break;
    }

    // Send the JSON message through the protocol
    SendText(message.dump());
}

void SendWakeWordDetected(const std::string &wake_word) {
    // Construct the JSON message
    json message;
    message["session_id"] = session_id_;
    message["type"] = "listen";
    message["state"] = "detect";
    message["text"] = wake_word;

    // Send the JSON message using the existing SendText method
    SendText(message.dump());
}

void Protocol::SendStartListening(ListeningMode mode) {
    // Get the session ID from the protocol instance
    const std::string& session_id = GetSessionId();

    // Convert ListeningMode enum to string representation
    std::string mode_str;
    switch (mode) {
        case kListeningModeManualStop:
            mode_str = "manual_stop";
            break;
        case kListeningModeAutoStop:
            mode_str = "auto_stop";
            break;
        case kListeningModeContinuous:
            mode_str = "continuous";
            break;
        default:
            mode_str = "unknown";
            break;
    }

    // Construct the JSON message following the same pattern as other protocol functions
    std::string json_message = "{\"session_id\":\"" + session_id + 
                              "\",\"type\":\"listen\",\"state\":\"start\",\"mode\":\"" + 
                              mode_str + "\"}";

    // Send the JSON message over the network
    SendText(json_message);
}

void Protocol::SendStopListening() {
    // Create JSON message similar to SendStartListening and SendWakeWordDetected
    // Format: {"type":"listen", "state":"stop", "session_id":"..." }

    Json::Value root;
    root["type"] = "listen";
    root["state"] = "stop";

    // Add session ID if available
    if (!session_id_.empty()) {
        root["session_id"] = session_id_;
    }

    // Convert JSON to string and send
    Json::StreamWriterBuilder builder;
    std::string json_message = Json::writeString(builder, root);

    // Send the message using the base interface
    SendText(json_message);
}

bool Protocol::SendMcpMessage(const std::string& message) {
    // Construct MCP message payload with proper JSON structure
    // Include session_id_ to maintain context and message type
    std::string payload = "{"
        "\"type\":\"mcp_message\","
        "\"session_id\":\"" + session_id_ + "\","
        "\"payload\":" + message + "}";

    // Send the constructed message via WebSocket
    return SendText(payload);
}

bool Protocol::IsTimeout() const {
    // Get current time using steady clock
    auto current_time = std::chrono::steady_clock::now();

    // Calculate elapsed time since last incoming message
    auto elapsed_time = std::chrono::duration_cast<std::chrono::seconds>(
        current_time - last_incoming_time_
    );

    // Check if elapsed time exceeds timeout threshold (120 seconds)
    if (elapsed_time.count() > kTimeoutSeconds) {
        // Log error when timeout occurs
        ESP_LOGE("Protocol", "Protocol timeout detected: %ld seconds since last incoming data",
                 elapsed_time.count());
        return true;
    }

    return false;
}

bool WebsocketProtocol::Start() {
    // Initialize network resources
    auto* network = Board::GetInstance().GetNetwork();
    if (!network) {
        LOG_ERROR("Failed to get network instance");
        return false;
    }

    // Create WebSocket instance
    websocket_ = network->CreateWebSocket(1);
    if (!websocket_) {
        LOG_ERROR("Failed to create WebSocket instance");
        return false;
    }

    // Set up WebSocket headers
    std::map<std::string, std::string> headers;
    headers["Content-Type"] = "application/json";

    // Get application settings for WebSocket connection
    auto& settings = Application::GetInstance().GetSettings();
    if (settings.HasValue("websocket_url")) {
        websocket_url_ = settings.GetString("websocket_url");
    } else {
        websocket_url_ = DEFAULT_WEBSOCKET_URL;
    }

    // Set additional headers from system info
    auto& system_info = SystemInfo::GetInstance();
    headers["User-Agent"] = system_info.GetDeviceId();
    headers["X-Device-ID"] = system_info.GetDeviceId();
    headers["X-App-Version"] = system_info.GetVersion();

    // Connect to WebSocket server
    if (!websocket_->Connect(websocket_url_, headers)) {
        LOG_ERROR("Failed to connect to WebSocket server: %s", websocket_url_.c_str());
        return false;
    }

    // Send hello message to server
    std::string hello_message = "{\"type\":\"hello\",\"device_id\":\"" + 
                               system_info.GetDeviceId() + "\"}";
    if (!websocket_->Send(hello_message)) {
        LOG_ERROR("Failed to send hello message");
        return false;
    }

    // Wait for server hello response
    std::string response;
    if (!websocket_->Receive(response, WEBSOCKET_TIMEOUT_MS)) {
        LOG_ERROR("Timeout waiting for server hello response");
        return false;
    }

    // Validate server response
    if (response.find("\"type\":\"server_hello\"") == std::string::npos) {
        LOG_ERROR("Invalid server response: %s", response.c_str());
        return false;
    }

    // Connection established successfully
    is_connected_ = true;

    // Trigger audio channel opened event if callback is set
    if (on_audio_channel_opened_) {
        on_audio_channel_opened_();
    }

    LOG_INFO("WebSocket connection established successfully");
    return true;
}

void WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    if (!websocket_ || !websocket_->IsConnected()) {
        return;
    }

    std::vector<uint8_t> buffer;

    switch (version_) {
        case 2: {
            // Serialize using BinaryProtocol2
            BinaryProtocol2::Serialize(*packet, buffer);
            break;
        }
        case 3: {
            // Serialize using BinaryProtocol3
            BinaryProtocol3::Serialize(*packet, buffer);
            break;
        }
        default: {
            // For default version, send raw payload bytes
            buffer = packet->payload();
            break;
        }
    }

    // Send binary data through websocket
    websocket_->Send(buffer.data(), buffer.size(), true);
}

bool SendText(const std::string& text) {
    // Check if websocket is valid and connected
    if (!websocket_ || !websocket_->IsConnected()) {
        ESP_LOGE(TAG, "WebSocket is not connected, cannot send text message");
        SetError("WebSocket not connected");
        return false;
    }

    // Send the text message through websocket
    try {
        websocket_->Send(text);
        return true;
    } catch (const std::exception& e) {
        ESP_LOGE(TAG, "Failed to send text message: %s", e.what());
        SetError(std::string("Failed to send message: ") + e.what());
        return false;
    }
}

void WebsocketProtocol::OpenAudioChannel() {
    // Get configuration from Settings
    std::string url = Settings::GetInstance().GetServerUrl();
    std::string token = Settings::GetInstance().GetToken();
    std::string version = Settings::GetInstance().GetProtocolVersion();
    std::string device_id = Settings::GetInstance().GetDeviceId();
    std::string client_id = Settings::GetInstance().GetClientId();

    // Create WebSocket instance
    websocket_ = Board::GetInstance().GetNetwork()->CreateWebSocket();

    // Set up WebSocket headers
    websocket_->SetHeader("Authorization", "Bearer " + token);
    websocket_->SetHeader("Protocol-Version", version);
    websocket_->SetHeader("Device-Id", device_id);
    websocket_->SetHeader("Client-Id", client_id);

    // Set up WebSocket callbacks
    websocket_->SetOnData([this](const std::vector<uint8_t>& data) {
        // Process incoming data - determine if it's binary audio or JSON message
        if (data.empty()) return;

        // Check if it's a binary audio packet (first byte indicates type)
        if (data[0] == 0x01) {  // Binary audio data
            // Forward audio data to audio processor
            OnAudioDataReceived(data);
        } else {  // JSON message
            // Parse and handle JSON message
            std::string json_str(data.begin(), data.end());
            cJSON* json = cJSON_Parse(json_str.c_str());
            if (json != nullptr) {
                // Handle server hello message
                if (cJSON_HasObjectItem(json, "type")) {
                    cJSON* type = cJSON_GetObjectItem(json, "type");
                    if (cJSON_IsString(type) && strcmp(type->valuestring, "hello") == 0) {
                        ParseServerHello(json);
                    }
                }
                cJSON_Delete(json);
            }
        }
    });

    websocket_->SetOnDisconnected([this]() {
        // Trigger audio channel closed callback
        if (on_audio_channel_closed_) {
            on_audio_channel_closed_();
        }
        // Reset websocket pointer
        websocket_ = nullptr;
    });

    // Connect to WebSocket server
    if (!websocket_->Connect(url)) {
        // Handle connection failure
        SetError("Failed to connect to WebSocket server");
        return;
    }

    // Send hello message to server
    std::string hello_message = GetHelloMessage();
    SendText(hello_message);

    // Wait for server hello response
    EventBits_t bits = xEventGroupWaitBits(
        websocket_event_group_,
        WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear bits on exit
        pdFALSE,  // Wait for any bit
        pdMS_TO_TICKS(5000)  // 5 second timeout
    );

    if (!(bits & WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT)) {
        // Timeout waiting for server hello
        SetError("Timeout waiting for server hello response");
        websocket_->Disconnect();
        websocket_ = nullptr;
        return;
    }

    // Notify that audio channel is opened
    if (on_audio_channel_opened_) {
        on_audio_channel_opened_();
    }
}

std::string WebsocketProtocol::GetHelloMessage() {
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        return "";
    }

    // Add type field
    cJSON_AddStringToObject(root, "type", "hello");

    // Add version field
    cJSON_AddStringToObject(root, "version", "1.0");

    // Add features object
    cJSON* features = cJSON_CreateObject();
    if (features) {
        cJSON_AddFalseToObject(features, "mcp");
#ifdef CONFIG_USE_SERVER_AEC
        cJSON_AddTrueToObject(features, "aec");
#else
        cJSON_AddFalseToObject(features, "aec");
#endif
        cJSON_AddItemToObject(root, "features", features);
    }

    // Add transport field
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add audio_params object
    cJSON* audio_params = cJSON_CreateObject();
    if (audio_params) {
        cJSON_AddStringToObject(audio_params, "format", "pcm");
        cJSON_AddNumberToObject(audio_params, "sample_rate", 16000);
        cJSON_AddNumberToObject(audio_params, "channels", 1);
        cJSON_AddNumberToObject(audio_params, "frame_duration", 20);
        cJSON_AddItemToObject(root, "audio_params", audio_params);
    }

    // Convert to string and clean up
    char* json_string = cJSON_PrintUnformatted(root);
    std::string result;

    if (json_string) {
        result = json_string;
        cJSON_free(json_string);
    }

    cJSON_Delete(root);
    return result;
}

void WebsocketProtocol::ParseServerHello(const cJSON* root) {
    // Extract session_id from the hello message
    const cJSON* session_id_item = cJSON_GetObjectItem(root, "session_id");
    if (session_id_item != nullptr && cJSON_IsString(session_id_item)) {
        std::string session_id = cJSON_GetStringValue(session_id_item);
        ESP_LOGI(TAG, "Received session ID: %s", session_id.c_str());
        session_id_ = session_id;
    } else {
        ESP_LOGE(TAG, "Failed to parse session_id from hello message");
        return;
    }

    // Extract transport type from the hello message
    const cJSON* transport_item = cJSON_GetObjectItem(root, "transport");
    if (transport_item != nullptr && cJSON_IsString(transport_item)) {
        std::string transport = cJSON_GetStringValue(transport_item);
        ESP_LOGI(TAG, "Received transport: %s", transport.c_str());

        // Validate that transport is websocket
        if (transport != "websocket") {
            ESP_LOGE(TAG, "Unsupported transport type: %s", transport.c_str());
            return;
        }
    } else {
        ESP_LOGE(TAG, "Failed to parse transport from hello message");
        return;
    }

    // Extract audio_params from the hello message
    const cJSON* audio_params_item = cJSON_GetObjectItem(root, "audio_params");
    if (audio_params_item != nullptr && cJSON_IsObject(audio_params_item)) {
        // Extract sample_rate from audio_params
        const cJSON* sample_rate_item = cJSON_GetObjectItem(audio_params_item, "sample_rate");
        if (sample_rate_item != nullptr && cJSON_IsNumber(sample_rate_item)) {
            server_sample_rate_ = static_cast<uint32_t>(cJSON_GetNumberValue(sample_rate_item));
            ESP_LOGI(TAG, "Received server sample rate: %u Hz", server_sample_rate_);
        } else {
            ESP_LOGE(TAG, "Failed to parse sample_rate from audio_params");
            return;
        }

        // Extract frame_duration from audio_params
        const cJSON* frame_duration_item = cJSON_GetObjectItem(audio_params_item, "frame_duration");
        if (frame_duration_item != nullptr && cJSON_IsNumber(frame_duration_item)) {
            server_frame_duration_ = static_cast<uint32_t>(cJSON_GetNumberValue(frame_duration_item));
            ESP_LOGI(TAG, "Received server frame duration: %u ms", server_frame_duration_);
        } else {
            ESP_LOGE(TAG, "Failed to parse frame_duration from audio_params");
            return;
        }
    } else {
        ESP_LOGE(TAG, "Failed to parse audio_params from hello message");
        return;
    }

    // Set the event bit to indicate successful handshake completion
    if (websocket_event_group_ != nullptr) {
        xEventGroupSetBits(websocket_event_group_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);
    }
}
